script:
(function (root_element) {
  const $ = (sel) => root_element.querySelector(sel) || document.querySelector(sel);

  // Elements
  const loadBtn = $("#load_report");
  const resetBtn = $("#reset_filters_btn");
  const toggleAutoRefreshBtn = $("#toggle_auto_refresh");
  let actionCenterMainBtn = $("#open_action_center_main");
  let soStatusBoardBtn = $("#open_so_status_board");
  let createSalesOrderBtn = $("#open_sales_order_creator");
  const fromDateEl = $("#from_date");
  const toDateEl = $("#to_date");
  const companyEl = $("#company_filter");
  const statusEl = $("#status_filter");
  const workstationEl = $("#workstation_filter");
  const operationEl = $("#operation_filter");
  const workOrderEl = $("#work_order_filter");
  const jobCardEl = $("#job_card_filter");
  let salesOrderEl = $("#sales_order_filter");
  const errorEl = $("#error_box");
  const loadingEl = $("#loading_spinner");
  const lastRefreshEl = $("#last_refresh");
  const refreshTimerEl = $("#refresh_timer");
  const cardsContainer = $("#production_cards_container");
  const noDataEl = $("#no_data_message");

  // Stats elements
  const statTotal = $("#stat_total");
  const statWip = $("#stat_wip");
  const statOpen = $("#stat_open");
  const statCompleted = $("#stat_completed");
  const statWorkOrder = $("#stat_work_order");
  const statJobCard = $("#stat_job_card");

  // State
  let jobCardsData = [];
  let autoRefreshInterval = null;
  let timeCounterIntervals = {};
  let autoRefreshEnabled = false;
  let refreshCountdown = 30;
  let controlDialog = null;

  // Helpers
  function ymd(d) {
    if (!d) return "";
    if (typeof d === "string") return d.slice(0, 10);
    return d.toISOString().slice(0, 10);
  }

  function fmt(n) {
    return Number(n || 0).toLocaleString(undefined, { maximumFractionDigits: 0 });
  }

  function nowStamp() {
    const d = new Date();
    return d.toLocaleString(undefined, {
      year: "numeric",
      month: "short",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit"
    });
  }

  function formatTime(seconds) {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    return `${String(hours).padStart(2, '0')} : ${String(minutes).padStart(2, '0')} : ${String(secs).padStart(2, '0')}`;
  }

  function calculateElapsedTime(startTime) {
    if (!startTime) return 0;
    const start = new Date(startTime);
    const now = new Date();
    return Math.floor((now - start) / 1000); // seconds
  }

  function formatDateTime(dt) {
    if (!dt) return "";
    const d = new Date(dt);
    return d.toLocaleString(undefined, {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit"
    });
  }

  function escapeHtml(value) {
    return String(value == null ? "" : value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function sortDocNamesDesc(values) {
    return [...new Set((values || []).map(v => String(v || "").trim()).filter(Boolean))]
      .sort((a, b) => b.localeCompare(a, undefined, { numeric: true, sensitivity: "base" }));
  }

  function normalizeJobCardContext(jc) {
    if (!jc) return null;
    const completedQty = Number(jc.completed_qty != null ? jc.completed_qty : jc.total_completed_qty || 0);
    return Object.assign({}, jc, {
      job_card: jc.job_card || jc.name || "",
      completed_qty: completedQty,
      total_completed_qty: Number(jc.total_completed_qty != null ? jc.total_completed_qty : completedQty),
      start_time: jc.start_time || jc.actual_start_date || jc.started_time || "",
      production_item: jc.production_item || jc.item_code || ""
    });
  }

  function mergeMissingSeed(target, source) {
    Object.keys(source || {}).forEach((key) => {
      const currentValue = target[key];
      if (
        currentValue === undefined ||
        currentValue === null ||
        currentValue === "" ||
        (typeof currentValue === "number" && !currentValue)
      ) {
        target[key] = source[key];
      }
    });
    return target;
  }

  function buildSeedFromJobCard(jc) {
    const row = normalizeJobCardContext(jc);
    if (!row) return {};
    return {
      company: row.company || "",
      item_code: row.production_item || "",
      bom_no: row.bom_no || "",
      qty: Math.max(Number(row.for_quantity || 0) - Number(row.completed_qty || 0), 1),
      sales_order: row.sales_order || "",
      production_plan: row.production_plan || "",
      work_order: row.work_order || "",
      source_warehouse: row.source_warehouse || "",
      wip_warehouse: row.wip_warehouse || "",
      target_warehouse: row.fg_warehouse || row.target_warehouse || "",
      scrap_warehouse: row.scrap_warehouse || ""
    };
  }

  function applyLayoutTuning() {
    if (document.getElementById("live_wo_layout_tuning")) return;
    const style = document.createElement("style");
    style.id = "live_wo_layout_tuning";
    style.textContent = `
      #production_cards_container {
        width: 60%;
        max-width: 60%;
        min-width: 360px;
        display: grid;
        grid-template-columns: 1fr;
        gap: 16px;
      }
      @media (max-width: 1200px) {
        #production_cards_container {
          width: 100%;
          max-width: 100%;
          min-width: 0;
        }
      }
    `;
    document.head.appendChild(style);
  }

  function ensureSalesOrderFilter() {
    if (salesOrderEl) return;
    const anchor = workOrderEl || jobCardEl || operationEl;
    if (!anchor || !anchor.parentElement) return;
    const fieldWrap = document.createElement("div");
    fieldWrap.className = anchor.parentElement.className || "";
    const label = document.createElement("label");
    label.textContent = "Sales Order";
    const select = document.createElement("select");
    select.id = "sales_order_filter";
    select.className = anchor.className || "";
    select.innerHTML = '<option value="">All Sales Orders</option>';
    select.style.width = "100%";
    fieldWrap.appendChild(label);
    fieldWrap.appendChild(select);
    anchor.parentElement.insertAdjacentElement("afterend", fieldWrap);
    salesOrderEl = select;
  }

  function ensureMainActionButton() {
    if (actionCenterMainBtn) return;
    const anchor = toggleAutoRefreshBtn || loadBtn || resetBtn;
    if (!anchor || !anchor.parentElement) return;
    const btn = document.createElement("button");
    btn.id = "open_action_center_main";
    btn.type = "button";
    btn.textContent = "Action Center";
    btn.style.padding = "10px 16px";
    btn.style.border = "none";
    btn.style.borderRadius = "8px";
    btn.style.background = "linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%)";
    btn.style.color = "#fff";
    btn.style.fontWeight = "700";
    btn.style.cursor = "pointer";
    btn.style.boxShadow = "0 2px 8px rgba(2,132,199,0.3)";
    btn.setAttribute("onclick", "window.openActionCenter && window.openActionCenter(window.getDefaultActionSeed ? window.getDefaultActionSeed() : {})");
    btn.onclick = () => window.openActionCenter(getDefaultActionSeed());
    anchor.parentElement.appendChild(btn);
    actionCenterMainBtn = btn;
  }

  function ensureSoStatusBoardButton() {
    if (soStatusBoardBtn) return;
    const anchor = actionCenterMainBtn || toggleAutoRefreshBtn || loadBtn;
    if (!anchor || !anchor.parentElement) return;
    const btn = document.createElement("button");
    btn.id = "open_so_status_board";
    btn.type = "button";
    btn.textContent = "SO Status Board";
    btn.style.padding = "10px 16px";
    btn.style.border = "none";
    btn.style.borderRadius = "8px";
    btn.style.background = "linear-gradient(135deg,#7c3aed 0%,#6d28d9 100%)";
    btn.style.color = "#fff";
    btn.style.fontWeight = "700";
    btn.style.cursor = "pointer";
    btn.style.boxShadow = "0 2px 8px rgba(109,40,217,0.3)";
    btn.onclick = () => window.openSalesOrderStatusBoard();
    anchor.parentElement.appendChild(btn);
    soStatusBoardBtn = btn;
  }

  function ensureSalesOrderCreateButton() {
    if (createSalesOrderBtn && createSalesOrderBtn.remove) {
      createSalesOrderBtn.remove();
      createSalesOrderBtn = null;
    }
  }

  function debounce(fn, wait = 300) {
    let t = null;
    return function(...args) {
      clearTimeout(t);
      t = setTimeout(() => fn.apply(this, args), wait);
    };
  }

  function getStatusColor(status) {
    const statusLower = (status || "").toLowerCase();
    if (statusLower.includes("work in progress") || statusLower.includes("wip")) {
      return { bg: "#fef3c7", text: "#92400e", border: "#fbbf24" };
    }
    if (statusLower.includes("open") || statusLower.includes("pending")) {
      return { bg: "#e5e7eb", text: "#374151", border: "#9ca3af" };
    }
    if (statusLower.includes("complete") || statusLower.includes("completed")) {
      return { bg: "#d1fae5", text: "#065f46", border: "#10b981" };
    }
    if (statusLower.includes("material transferred")) {
      return { bg: "#dbeafe", text: "#1e40af", border: "#3b82f6" };
    }
    if (statusLower.includes("hold") || statusLower.includes("pause")) {
      return { bg: "#fee2e2", text: "#991b1b", border: "#ef4444" };
    }
    return { bg: "#f3f4f6", text: "#374151", border: "#9ca3af" };
  }

  // Load data from API
  async function loadData() {
    if (loadingEl) loadingEl.style.display = "block";
    if (errorEl) errorEl.innerHTML = "";

    const args = {
      from_date: ymd(fromDateEl?.value) || "",
      to_date: ymd(toDateEl?.value) || "",
      status: statusEl?.value || "",
      work_order: workOrderEl?.value || "",
      job_card: jobCardEl?.value || "",
      sales_order: salesOrderEl?.value || "",
      company: companyEl?.value || "",
      workstation: workstationEl?.value || "",
      operation: operationEl?.value || "",
    };

    try {
      const response = await frappe.call({
        method: "live_production_api",
        args: args,
        callback: (r) => {
          if (r.message && r.message.job_cards) {
            jobCardsData = r.message.job_cards || [];
            renderCards();
            updateStats();
            populateFilters(r.message.job_cards);
            if (lastRefreshEl) lastRefreshEl.textContent = nowStamp();
          } else {
            jobCardsData = [];
            renderCards();
            updateStats();
          }
          if (loadingEl) loadingEl.style.display = "none";
        },
        error: (r) => {
          console.error("API Error:", r);
          if (errorEl) errorEl.innerHTML = `<div style="padding:12px;background:#fee2e2;border-radius:8px;color:#991b1b;font-weight:600;">Error loading data: ${r.message || "Unknown error"}</div>`;
          if (loadingEl) loadingEl.style.display = "none";
        }
      });
    } catch (err) {
      console.error("Load error:", err);
      if (errorEl) errorEl.innerHTML = `<div style="padding:12px;background:#fee2e2;border-radius:8px;color:#991b1b;font-weight:600;">Error: ${err.message}</div>`;
      if (loadingEl) loadingEl.style.display = "none";
    }
  }

  // Populate filter dropdowns
  function populateFilters(data) {
    if (!data || data.length === 0) return;

    // Populate Work Order filter
    if (workOrderEl) {
      const workOrders = sortDocNamesDesc(data.map(jc => jc.work_order));
      const currentValue = workOrderEl.value;
      workOrderEl.innerHTML = '<option value="">All Work Orders</option>';
      workOrders.forEach(wo => {
        const option = document.createElement('option');
        option.value = wo;
        option.textContent = wo;
        workOrderEl.appendChild(option);
      });
      if (currentValue) workOrderEl.value = currentValue;
    }

    // Populate Job Card filter
    if (jobCardEl) {
      const jobCards = sortDocNamesDesc(data.map(jc => jc.job_card));
      const currentValue = jobCardEl.value;
      jobCardEl.innerHTML = '<option value="">All Job Cards</option>';
      jobCards.forEach(jc => {
        const option = document.createElement('option');
        option.value = jc;
        option.textContent = jc;
        jobCardEl.appendChild(option);
      });
      if (currentValue) jobCardEl.value = currentValue;
    }

    // Populate Sales Order filter
    if (salesOrderEl) {
      const salesOrders = sortDocNamesDesc(data.map(jc => jc.sales_order));
      const currentValue = salesOrderEl.value;
      salesOrderEl.innerHTML = '<option value="">All Sales Orders</option>';
      salesOrders.forEach(so => {
        const option = document.createElement('option');
        option.value = so;
        option.textContent = so;
        salesOrderEl.appendChild(option);
      });
      if (currentValue) salesOrderEl.value = currentValue;
    }

    // Populate Company filter
    if (companyEl) {
      const companies = [...new Set(data.map(jc => jc.company).filter(Boolean))].sort();
      const currentValue = companyEl.value;
      companyEl.innerHTML = '<option value="">All Companies</option>';
      companies.forEach(company => {
        const option = document.createElement('option');
        option.value = company;
        option.textContent = company;
        companyEl.appendChild(option);
      });
      if (currentValue) companyEl.value = currentValue;
    }

    // Populate Workstation filter
    if (workstationEl) {
      const workstations = [...new Set(data.map(jc => jc.workstation).filter(Boolean))].sort();
      const currentValue = workstationEl.value;
      workstationEl.innerHTML = '<option value="">All Workstations</option>';
      workstations.forEach(ws => {
        const option = document.createElement('option');
        option.value = ws;
        option.textContent = ws;
        workstationEl.appendChild(option);
      });
      if (currentValue) workstationEl.value = currentValue;
    }

    // Populate Operation filter
    if (operationEl) {
      const operations = [...new Set(data.map(jc => jc.operation).filter(Boolean))].sort();
      const currentValue = operationEl.value;
      operationEl.innerHTML = '<option value="">All Operations</option>';
      operations.forEach(op => {
        const option = document.createElement('option');
        option.value = op;
        option.textContent = op;
        operationEl.appendChild(option);
      });
      if (currentValue) operationEl.value = currentValue;
    }
  }

  // Update statistics
  function updateStats() {
    const total = jobCardsData.length;
    const wip = jobCardsData.filter(jc => (jc.status || "").toLowerCase().includes("work in progress")).length;
    const open = jobCardsData.filter(jc => {
      const s = (jc.status || "").toLowerCase();
      return s.includes("open") || s.includes("pending");
    }).length;
    const completed = jobCardsData.filter(jc => {
      const s = (jc.status || "").toLowerCase();
      return s.includes("complete");
    }).length;

    // Count unique work orders and job cards
    const uniqueWorkOrders = new Set(jobCardsData.map(jc => jc.work_order).filter(Boolean));
    const uniqueJobCards = new Set(jobCardsData.map(jc => jc.job_card).filter(Boolean));

    if (statTotal) statTotal.textContent = fmt(total);
    if (statWip) statWip.textContent = fmt(wip);
    if (statOpen) statOpen.textContent = fmt(open);
    if (statCompleted) statCompleted.textContent = fmt(completed);
    if (statWorkOrder) statWorkOrder.textContent = fmt(uniqueWorkOrders.size);
    if (statJobCard) statJobCard.textContent = fmt(uniqueJobCards.size);
  }

  // Create live time counter
  function createTimeCounter(cardId, startTime) {
    // Clear existing interval for this card
    if (timeCounterIntervals[cardId]) {
      clearInterval(timeCounterIntervals[cardId]);
    }

    const counterEl = $(`#time_counter_${cardId}`);
    if (!counterEl) return;

    function updateCounter() {
      const elapsed = calculateElapsedTime(startTime);
      if (counterEl) {
        counterEl.textContent = formatTime(elapsed);
      }
    }

    updateCounter(); // Initial update
    timeCounterIntervals[cardId] = setInterval(updateCounter, 1000);
  }

  // Render production cards
  function renderCards() {
    if (!cardsContainer) return;

    // Clear all time counter intervals
    Object.values(timeCounterIntervals).forEach(interval => clearInterval(interval));
    timeCounterIntervals = {};

    if (jobCardsData.length === 0) {
      cardsContainer.innerHTML = "";
      if (noDataEl) noDataEl.style.display = "block";
      return;
    }

    if (noDataEl) noDataEl.style.display = "none";

    cardsContainer.innerHTML = jobCardsData.map((jc, idx) => {
      const cardId = `jc_${idx}_${(jc.job_card || "").replace(/[^a-zA-Z0-9]/g, "_")}`;
      const status = jc.status || "Unknown";
      const statusColors = getStatusColor(status);
      const startTime = jc.start_time;
      const isActive = status.toLowerCase().includes("work in progress");
      const isOpen = status.toLowerCase().includes("open") || status.toLowerCase().includes("pending") || status.toLowerCase().includes("material transferred");
      const isCompleted = status.toLowerCase().includes("complete");

      // Calculate progress percentage
      const totalQty = jc.for_quantity || 0;
      const completedQty = jc.completed_qty || 0;
      const progress = totalQty > 0 ? (completedQty / totalQty) * 100 : 0;

      return `
        <div class="production-card" style="background:#fff;border-radius:12px;padding:20px;box-shadow:0 2px 8px rgba(0,0,0,0.08);border-left:4px solid ${statusColors.border};">
          <!-- Header: Operation Name -->
          <div style="margin-bottom:16px;">
            <h3 style="margin:0 0 8px;font-size:18px;font-weight:800;color:#1e293b;display:flex;align-items:center;gap:8px;">
              <span>${jc.operation || "N/A"}</span>
              <span style="font-size:14px;font-weight:600;color:#64748b;">- ${jc.item_name || jc.production_item || "N/A"}</span>
            </h3>
            <div style="display:flex;gap:12px;flex-wrap:wrap;font-size:13px;color:#64748b;">
              <a href="/app/job-card/${encodeURIComponent(jc.job_card || "")}" target="_blank" style="color:#3b82f6;text-decoration:none;font-weight:600;">📋 ${jc.job_card || "N/A"}</a>
              <a href="/app/work-order/${encodeURIComponent(jc.work_order || "")}" target="_blank" style="color:#3b82f6;text-decoration:none;font-weight:600;">📦 ${jc.work_order || "N/A"}</a>
              ${jc.sales_order ? `<a href="/app/sales-order/${encodeURIComponent(jc.sales_order)}" target="_blank" style="color:#3b82f6;text-decoration:none;font-weight:600;">🛒 ${jc.sales_order}</a>` : ""}
              ${jc.production_plan ? `<a href="/app/production-plan/${encodeURIComponent(jc.production_plan)}" target="_blank" style="color:#3b82f6;text-decoration:none;font-weight:600;">🗂 ${jc.production_plan}</a>` : ""}
              ${jc.workstation ? `<span>🏭 ${jc.workstation}</span>` : ""}
            </div>
          </div>

          <!-- Live Time Counter -->
          <div style="background:#f8fafc;border-radius:8px;padding:20px;margin-bottom:16px;text-align:center;border:2px solid #e5e7eb;">
            <div style="font-size:12px;color:#64748b;margin-bottom:8px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;">Elapsed Time</div>
            <div id="time_counter_${cardId}" style="font-size:32px;font-weight:900;color:#1e293b;font-family:'Courier New',monospace;letter-spacing:2px;">
              ${isActive && startTime ? formatTime(calculateElapsedTime(startTime)) : "00 : 00 : 00"}
            </div>
            ${startTime ? `<div style="font-size:11px;color:#64748b;margin-top:8px;">Started: ${formatDateTime(startTime)}</div>` : ""}
          </div>

          <!-- Status Badge -->
          <div style="margin-bottom:16px;">
            <span style="display:inline-block;padding:8px 16px;background:${statusColors.bg};color:${statusColors.text};border:1px solid ${statusColors.border};border-radius:8px;font-size:13px;font-weight:700;">
              ${status}
            </span>
          </div>

          <!-- Quantity Progress -->
          <div style="margin-bottom:16px;">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
              <span style="font-size:14px;font-weight:700;color:#334155;">Quantity</span>
              <span style="font-size:16px;font-weight:800;color:#1e293b;">${fmt(completedQty)} / ${fmt(totalQty)}</span>
            </div>
            <div style="width:100%;height:8px;background:#e5e7eb;border-radius:4px;overflow:hidden;">
              <div style="width:${Math.min(progress, 100)}%;height:100%;background:linear-gradient(90deg,#3b82f6 0%,#2563eb 100%);transition:width 0.3s;"></div>
            </div>
            <div style="font-size:12px;color:#64748b;margin-top:4px;">${progress.toFixed(1)}% Complete</div>
          </div>

          <!-- Additional Info -->
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px;font-size:12px;">
            ${jc.expected_start_date ? `<div><span style="color:#64748b;">Expected Start:</span><br><span style="font-weight:600;color:#334155;">${formatDateTime(jc.expected_start_date)}</span></div>` : ""}
            ${jc.expected_end_date ? `<div><span style="color:#64748b;">Expected End:</span><br><span style="font-weight:600;color:#334155;">${formatDateTime(jc.expected_end_date)}</span></div>` : ""}
            ${jc.time_required ? `<div><span style="color:#64748b;">Time Required:</span><br><span style="font-weight:600;color:#334155;">${fmt(jc.time_required)} mins</span></div>` : ""}
            ${jc.total_time_in_mins ? `<div><span style="color:#64748b;">Total Time:</span><br><span style="font-weight:600;color:#334155;">${fmt(jc.total_time_in_mins)} mins</span></div>` : ""}
          </div>

          <!-- Action Buttons -->
          <div style="display:flex;gap:8px;flex-wrap:wrap;">
            ${isOpen ? `<button onclick="startJobCard('${jc.job_card}')" style="padding:10px 20px;background:linear-gradient(135deg,#10b981 0%,#059669 100%);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 2px 8px rgba(16,185,129,0.3);">▶ Start Job</button>` : ""}
            ${isActive ? `<button onclick="partialJobCard('${jc.job_card}')" style="padding:10px 20px;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 2px 8px rgba(245,158,11,0.3);">⏸ Pause Job</button>` : ""}
            ${isActive ? `<button onclick="completeJobCard('${jc.job_card}')" style="padding:10px 20px;background:linear-gradient(135deg,#3b82f6 0%,#2563eb 100%);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 2px 8px rgba(59,130,246,0.3);">✓ Complete Job</button>` : ""}
            <button onclick="openWorkOrderActionCenter('${jc.job_card}')" style="padding:10px 20px;background:linear-gradient(135deg,#06b6d4 0%,#0e7490 100%);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 2px 8px rgba(14,116,144,0.3);">⚙ WO Action</button>
            ${(jc.sales_order || jc.production_plan || jc.work_order) ? `<button onclick="showSmartSummaryByJobCard('${jc.job_card}')" style="padding:10px 20px;background:linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 2px 8px rgba(124,58,237,0.3);">📊 Smart View</button>` : ""}
            <a href="/app/job-card/${encodeURIComponent(jc.job_card || "")}" target="_blank" style="padding:10px 20px;background:#f1f5f9;color:#334155;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;text-decoration:none;display:inline-block;">📄 View Details</a>
          </div>
        </div>
      `;
    }).join("");

    // Initialize time counters for active job cards
    jobCardsData.forEach((jc, idx) => {
      const cardId = `jc_${idx}_${(jc.job_card || "").replace(/[^a-zA-Z0-9]/g, "_")}`;
      const status = (jc.status || "").toLowerCase();
      const isActive = status.includes("work in progress");
      if (isActive && jc.start_time) {
        createTimeCounter(cardId, jc.start_time);
      }
    });
  }

  function getJobCardByName(jobCardName) {
    return (jobCardsData || []).find(jc => jc.job_card === jobCardName) || null;
  }

  async function getJobCardContext(jobCardName) {
    const current = getJobCardByName(jobCardName);
    if (current) return normalizeJobCardContext(current);
    const row = (await getDocList(
      "Job Card",
      { name: jobCardName },
      ["name", "company", "work_order", "operation", "status", "bom_no", "production_item", "for_quantity", "total_completed_qty", "sequence_id", "actual_start_date", "started_time"],
      1
    ))[0];
    return normalizeJobCardContext(row);
  }

  async function getJobCardSequenceWarning(jc, additionalQty) {
    if (!jc?.work_order || !Number(jc.sequence_id || 0)) return "";
    try {
      const rows = await getDocList(
        "Work Order Operation",
        [["Work Order Operation", "parent", "=", jc.work_order], ["Work Order Operation", "docstatus", "=", 1], ["Work Order Operation", "sequence_id", "<", jc.sequence_id]],
        ["name", "operation", "status", "completed_qty", "sequence_id"],
        100
      );
      if (!rows.length) return "";
      const targetQty = Number(jc.completed_qty || jc.total_completed_qty || 0) + Number(additionalQty || 0);
      const blockingRow = rows.find((row) => (
        String(row.status || "").toLowerCase() !== "completed" ||
        Number(row.completed_qty || 0) < targetQty
      ));
      if (!blockingRow) return "";
      return `Previous operation ${blockingRow.operation || blockingRow.name || ""} is not complete for Work Order ${jc.work_order}. ERPNext may block ${jc.operation || "this job card"} until sequence is finished.`;
    } catch (e) {
      return "";
    }
  }

  async function runControlAction(apiAction, payload, successText) {
    try {
      await frappe.call({
        method: "live_production_api",
        args: Object.assign({ action: apiAction }, payload || {})
      });
      frappe.show_alert({ message: successText, indicator: "green" }, 3);
      loadData();
    } catch (err) {
      frappe.show_alert({ message: "Action failed: " + (err.message || "Unknown error"), indicator: "red" }, 6);
    }
  }

  function normalizeEmployeesInput(raw) {
    if (!raw) return [];
    if (Array.isArray(raw)) {
      const vals = raw.map(v => {
        if (!v) return "";
        if (typeof v === "string") return v;
        if (typeof v === "object") return v.value || v.label || v.name || "";
        return "";
      }).filter(Boolean);
      return [...new Set(vals)];
    }
    const txt = String(raw).replace(/\n/g, ",");
    const parts = txt.split(",").map(x => x.trim()).filter(Boolean);
    return [...new Set(parts)];
  }

  async function openControlDialog(mode, jobCardName) {
    const jc = await getJobCardContext(jobCardName);
    if (!jc) {
      frappe.show_alert({ message: "Job Card not found in current list.", indicator: "orange" }, 4);
      return;
    }

    if (controlDialog) {
      controlDialog.hide();
      controlDialog = null;
    }

    const nowVal = frappe.datetime.now_datetime();
    const isStart = mode === "start";
    const isPartial = mode === "partial";
    const isComplete = mode === "complete";
    const remainingQty = Math.max(Number(jc.for_quantity || 0) - Number(jc.completed_qty || 0), 0);
    const initialSequenceWarning = await getJobCardSequenceWarning(jc, isComplete ? remainingQty : 0);

    controlDialog = new frappe.ui.Dialog({
      title: `${isStart ? "Start Job" : isPartial ? "Pause Job" : "Complete Job"} - ${jobCardName}`,
      fields: [
        { fieldtype: "HTML", fieldname: "requirements_help" },
        { fieldtype: "Section Break" },
        { fieldtype: "HTML", fieldname: "job_info" },
        { fieldtype: "Section Break" },
        {
          fieldtype: "MultiSelectPills",
          fieldname: "employees",
          label: "Employees",
          reqd: 1,
          get_data: function(txt) {
            return frappe.db.get_link_options("Employee", txt || "");
          }
        },
        { fieldtype: "Datetime", fieldname: "from_time", label: "From Time", default: nowVal, reqd: 1 },
        { fieldtype: "Datetime", fieldname: "to_time", label: "To Time", default: nowVal, reqd: isStart ? 0 : 1 },
        { fieldtype: "Float", fieldname: "completed_qty", label: "Completed Qty", default: isComplete ? remainingQty : 0, reqd: isStart ? 0 : 1 },
      ],
      primary_action_label: isStart ? "Start Job" : isPartial ? "Pause Job" : "Complete Job",
      primary_action: async (values) => {
        const payload = {
          job_card: jobCardName,
          employees: normalizeEmployeesInput(values.employees).join(","),
          from_time: values.from_time
        };
        if (!isStart) {
          payload.to_time = values.to_time;
          payload.completed_qty = values.completed_qty;
        }

        if (isPartial && Number(values.completed_qty || 0) <= 0) {
          frappe.show_alert({ message: "Completed Qty must be greater than 0.", indicator: "orange" }, 4);
          return;
        }
        if (isComplete && Number(values.completed_qty || 0) < 0) {
          frappe.show_alert({ message: "Completed Qty cannot be negative.", indicator: "orange" }, 4);
          return;
        }
        if (!payload.employees) {
          frappe.show_alert({ message: "Please enter at least one employee.", indicator: "orange" }, 4);
          return;
        }

        const proceed = async () => {
          controlDialog.hide();
          await runControlAction(
            isStart ? "start_job_card" : isPartial ? "update_production" : "complete_job_card",
            payload,
            isStart ? "Job Card started." : isPartial ? "Job paused with partial production saved." : "Job Card completed."
          );
        };

        const sequenceWarning = await getJobCardSequenceWarning(jc, isStart ? 0 : Number(values.completed_qty || 0));
        if (sequenceWarning) {
          frappe.confirm(sequenceWarning + " Continue anyway?", proceed, () => {});
          return;
        }

        await proceed();
      }
    });

    const html = `
      <div style="margin-bottom:10px;padding:12px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:8px;">
        <div style="font-weight:700;color:#1e293b;">${jc.job_card || ""}</div>
        <div style="font-size:12px;color:#64748b;margin-top:4px;">
          Work Order: <b>${jc.work_order || "-"}</b> |
          Operation: <b>${jc.operation || "-"}</b> |
          Qty: <b>${fmt(jc.completed_qty)} / ${fmt(jc.for_quantity)}</b>
        </div>
      </div>
    `;
    const requirementsHtml = `
      <div style="margin-bottom:10px;padding:10px;background:${isStart ? "#ecfdf5" : isPartial ? "#fffbeb" : "#eff6ff"};border:1px solid ${isStart ? "#bbf7d0" : isPartial ? "#fde68a" : "#bfdbfe"};border-radius:8px;font-size:12px;color:#334155;">
        ${isStart
          ? "Required: at least one Employee and From Time."
          : isPartial
            ? "Required: at least one Employee, From Time, To Time, and Completed Qty greater than 0. Use this to pause with partial production."
            : "Required: at least one Employee, From Time, To Time, and Completed Qty. Use remaining quantity to finish the Job Card."}
      </div>
      ${initialSequenceWarning ? `<div style="margin-bottom:10px;padding:10px;background:#fff7ed;border:1px solid #fdba74;border-radius:8px;font-size:12px;color:#9a3412;">${escapeHtml(initialSequenceWarning)}</div>` : ""}
    `;
    controlDialog.fields_dict.requirements_help.$wrapper.html(requirementsHtml);
    controlDialog.fields_dict.job_info.$wrapper.html(html);
    controlDialog.show();
  }

  window.startJobCard = function(jobCardName) {
    if (!jobCardName) return;
    openControlDialog("start", jobCardName);
  };

  window.partialJobCard = function(jobCardName) {
    if (!jobCardName) return;
    openControlDialog("partial", jobCardName);
  };

  window.completeJobCard = function(jobCardName) {
