    openControlDialog("complete", jobCardName);
  };

  function tableFromRows(rows, headers) {
    if (!rows || !rows.length) {
      return '<div style="padding:12px;color:#64748b;">No data found.</div>';
    }
    const thead = headers.map(h => `<th style="text-align:left;padding:8px;border-bottom:1px solid #e5e7eb;background:#f8fafc;">${escapeHtml(h)}</th>`).join("");
    const tbody = rows.map(r => `<tr>${headers.map(h => `<td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(r[h])}</td>`).join("")}</tr>`).join("");
    return `<div style="overflow:auto;max-height:220px;border:1px solid #e5e7eb;border-radius:8px;"><table style="width:100%;border-collapse:collapse;font-size:12px;"><thead><tr>${thead}</tr></thead><tbody>${tbody}</tbody></table></div>`;
  }

