  async function getDocValue(doctype, name, fieldname) {
    if (!doctype || !name || !fieldname) return "";
    try {
      const r = await frappe.call({
        method: "frappe.client.get_value",
        args: { doctype, filters: { name }, fieldname }
      });
      return r?.message?.[fieldname] || "";
