  }

  async function getDoc(doctype, name) {
    if (!doctype || !name) return null;
    try {
      const r = await frappe.call({
        method: "frappe.client.get",
        args: { doctype, name }
      });
      return r?.message || null;
    } catch (e) {
      return null;
    }
  }

  async function getItemDefaultsMap(itemCodes) {
    const codes = [...new Set((itemCodes || []).map(x => String(x || "").trim()).filter(Boolean))];
    if (!codes.length) return {};
    try {
      const r = await frappe.call({
        method: "frappe.client.get_list",
        args: {
          doctype: "Item",
          filters: [["Item", "name", "in", codes]],
          fields: ["name", "item_name", "stock_uom", "default_bom"],
          limit_page_length: Math.max(codes.length, 20)
        }
      });
      const rows = r?.message || [];
      return rows.reduce((acc, row) => {
        acc[row.name] = row;
        return acc;
      }, {});
    } catch (e) {
      return {};
    }
  }

