  async function hydrateActionSeed(seedOverride) {
    const seed = Object.assign({}, getDefaultActionSeed(), seedOverride || {});
    const firstCard = normalizeJobCardContext((jobCardsData || [])[0]);
    if (!seed.company) {
      seed.company = (frappe.defaults && (frappe.defaults.get_user_default?.("Company") || frappe.defaults.get_default?.("company"))) || "";
    }
    if (firstCard) {
      mergeMissingSeed(seed, buildSeedFromJobCard(firstCard));
    }

    if (!seed.sales_order && salesOrderEl?.value) seed.sales_order = salesOrderEl.value;
    if (!seed.work_order && workOrderEl?.value) seed.work_order = workOrderEl.value;
    if (!seed.job_card && jobCardEl?.value) seed.job_card = jobCardEl.value;

    if (seed.job_card && !seed.work_order) {
      const jcDoc = await getJobCardContext(seed.job_card);
      if (jcDoc) mergeMissingSeed(seed, buildSeedFromJobCard(jcDoc));
    }

    let workOrderDoc = null;
    if (seed.work_order) {
      workOrderDoc = await getDoc("Work Order", seed.work_order);
    }
    if (!workOrderDoc) {
      const woFilters = {};
      if (seed.sales_order) {
        woFilters.sales_order = seed.sales_order;
      } else if (seed.company) {
        woFilters.company = seed.company;
      }
      const latestWo = (await getDocList(
        "Work Order",
        woFilters,
        ["name", "company", "production_item", "bom_no", "qty", "sales_order", "production_plan", "source_warehouse", "wip_warehouse", "fg_warehouse", "scrap_warehouse"],
        1
      ))[0];
      if (latestWo?.name) {
        seed.work_order = latestWo.name;
        workOrderDoc = await getDoc("Work Order", latestWo.name);
      }
    }

    if (workOrderDoc) {
      mergeMissingSeed(seed, {
        company: workOrderDoc.company || "",
        item_code: workOrderDoc.production_item || "",
        bom_no: workOrderDoc.bom_no || "",
        qty: Math.max(Number(workOrderDoc.qty || 0) - Number(workOrderDoc.produced_qty || 0), 1),
        sales_order: workOrderDoc.sales_order || "",
        production_plan: workOrderDoc.production_plan || "",
        source_warehouse: workOrderDoc.source_warehouse || "",
        wip_warehouse: workOrderDoc.wip_warehouse || "",
        target_warehouse: workOrderDoc.fg_warehouse || "",
        scrap_warehouse: workOrderDoc.scrap_warehouse || ""
      });
    }

    if (!seed.production_plan) {
      const ppFilters = {};
      if (seed.company) {
        ppFilters.company = seed.company;
      }
      const latestPp = (await getDocList("Production Plan", ppFilters, ["name", "company"], 1))[0];
      if (latestPp?.name) seed.production_plan = latestPp.name;
    }

    let salesOrderDoc = null;
    if (seed.sales_order) {
      salesOrderDoc = await getDoc("Sales Order", seed.sales_order);
    }
    if (!salesOrderDoc) {
      const soFilters = {};
      if (seed.company) soFilters.company = seed.company;
      const latestSo = (await getDocList("Sales Order", soFilters, ["name"], 1))[0];
      if (latestSo?.name) {
        seed.sales_order = latestSo.name;
        salesOrderDoc = await getDoc("Sales Order", latestSo.name);
      }
    }
    if (salesOrderDoc) {
      mergeMissingSeed(seed, {
        company: salesOrderDoc.company || "",
        customer: salesOrderDoc.customer || "",
        source_warehouse: salesOrderDoc.set_warehouse || seed.source_warehouse || ""
      });
      if (!seed.item_code && Array.isArray(salesOrderDoc.items) && salesOrderDoc.items.length) {
        const soItem = salesOrderDoc.items[0] || {};
        seed.item_code = soItem.item_code || "";
        seed.qty = Number(soItem.qty || 1);
        seed.source_warehouse = seed.source_warehouse || soItem.warehouse || "";
      }
    }

    if (seed.item_code && !seed.bom_no) {
      const itemMap = await getItemDefaultsMap([seed.item_code]);
      seed.bom_no = itemMap[seed.item_code]?.default_bom || seed.bom_no || "";
    }

    return seed;
  }

  function renderStageCard(title, value, subtitle, colors) {
