  async function getManufacturingControlSnapshot(seed) {
    const salesOrder = seed.sales_order || "";
    const productionPlan = seed.production_plan || "";
    const workOrder = seed.work_order || "";

    const soRow = salesOrder
      ? (await getDocList("Sales Order", { name: salesOrder }, ["name", "status", "delivery_status", "billing_status", "per_delivered", "per_billed", "skip_delivery_note", "customer"], 1))[0]
      : null;
    const ppRows = productionPlan
      ? await getDocList("Production Plan", { name: productionPlan }, ["name", "status", "docstatus"], 5)
      : [];
    const woRows = workOrder
      ? await getDocList("Work Order", { name: workOrder }, ["name", "status", "docstatus", "qty", "produced_qty", "material_transferred_for_manufacturing", "transfer_material_against", "skip_transfer", "source_warehouse", "wip_warehouse", "fg_warehouse"], 10)
      : salesOrder
        ? await getDocList("Work Order", { sales_order: salesOrder }, ["name", "status", "docstatus", "qty", "produced_qty", "material_transferred_for_manufacturing", "transfer_material_against", "skip_transfer", "source_warehouse", "wip_warehouse", "fg_warehouse"], 50)
        : [];
    const woNames = [...new Set(woRows.map((row) => row.name).filter(Boolean))];
    const jcRows = woNames.length
      ? await getDocList("Job Card", [["Job Card", "work_order", "in", woNames]], ["name", "status", "work_order"], 200)
      : [];
    const stockRows = woNames.length
      ? await getDocList("Stock Entry", [["Stock Entry", "work_order", "in", woNames], ["Stock Entry", "docstatus", "!=", 2]], ["name", "purpose", "work_order", "docstatus", "fg_completed_qty"], 200)
      : [];
    const dnItemRows = salesOrder
      ? await getDocList("Delivery Note Item", { against_sales_order: salesOrder }, ["parent", "qty"], 200)
      : [];
    const dnNames = [...new Set(dnItemRows.map((row) => row.parent).filter(Boolean))];
    const dnRows = dnNames.length
      ? await getDocList("Delivery Note", [["Delivery Note", "name", "in", dnNames]], ["name", "status", "posting_date", "docstatus"], 50)
      : [];

    const transferredQty = woRows.reduce((acc, row) => acc + Number(row.material_transferred_for_manufacturing || 0), 0);
    const woQty = woRows.reduce((acc, row) => acc + Number(row.qty || 0), 0);
    const producedQty = woRows.reduce((acc, row) => acc + Number(row.produced_qty || 0), 0);
    const jcCompleted = jcRows.filter((row) => String(row.status || "").toLowerCase() === "completed").length;
    const manufactureEntries = stockRows.filter((row) => row.purpose === "Manufacture").length;
    const transferEntries = stockRows.filter((row) => row.purpose === "Material Transfer for Manufacture").length;

    const warnings = [];
    const selectedWo = woRows[0] || null;
    if (selectedWo) {
      if (!selectedWo.source_warehouse) warnings.push("Work Order source warehouse is missing.");
      if (!selectedWo.wip_warehouse) warnings.push("Work Order WIP warehouse is missing.");
      if (!selectedWo.fg_warehouse) warnings.push("Work Order target warehouse is missing.");
      if (Number(selectedWo.docstatus || 0) === 0) warnings.push("Work Order is still draft. Submit it before transfer or manufacture.");
      if (selectedWo.transfer_material_against === "Job Card") warnings.push("This Work Order transfers material against Job Card, not only against Work Order.");
      if (selectedWo.skip_transfer) warnings.push("This Work Order is marked to skip transfer. Manufacturing may go directly to Job Card / Manufacture.");
    }
    if (soRow?.status && String(soRow.status).toLowerCase() === "draft") warnings.push("Sales Order is draft. Downstream manufacturing links are limited until submit.");
    if (soRow?.skip_delivery_note) warnings.push("Sales Order is configured to skip Delivery Note.");

    return {
      soRow,
      ppRows,
      woRows,
      jcRows,
      stockRows,
      dnRows,
      metrics: {
        transferredQty,
        woQty,
        producedQty,
        jcCompleted,
        jcTotal: jcRows.length,
        manufactureEntries,
        transferEntries,
        deliveryCount: dnRows.length
      },
      warnings
    };
  }

  async function openDeliveryNoteCreator(seedOverride) {
