  async function getSalesOrderManufacturingSeed(salesOrderName, fallbackDate) {
    const today = fallbackDate || frappe.datetime.now_date();
    const so = await getDoc("Sales Order", salesOrderName);
    if (!so) {
      return {
        sales_order: salesOrderName || "",
        customer: "",
        company: "",
        docstatus: 0,
        can_link: false,
        warning: salesOrderName ? "Sales Order could not be loaded." : "",
        lines: []
      };
    }

    const canLink = Number(so.docstatus || 0) === 1;
    const items = Array.isArray(so.items) ? so.items : [];
    const itemDefaults = await getItemDefaultsMap(items.map(row => row.item_code));
    const lines = items
      .filter(row => row.item_code)
      .map((row) => {
        const qty = Number(row.qty || 0);
        const deliveredQty = Number(row.delivered_qty || 0);
        const workOrderQty = Number(row.work_order_qty || 0);
        const conversionFactor = Number(row.conversion_factor || 1);
        const pendingQty = Math.max((qty - Math.max(workOrderQty, deliveredQty, 0)) * conversionFactor, 0);
        const draftQty = Math.max(qty * conversionFactor, 0);
        const defaults = itemDefaults[row.item_code] || {};
        return {
          item_code: row.item_code || "",
          item_name: defaults.item_name || row.item_name || "",
          bom_no: row.bom_no || defaults.default_bom || "",
          stock_uom: defaults.stock_uom || row.stock_uom || "",
          qty: canLink ? pendingQty : draftQty,
          planned_qty: canLink ? pendingQty : draftQty,
          warehouse: row.warehouse || "",
          delivery_date: row.delivery_date || so.delivery_date || today,
          sales_order: so.name || "",
          sales_order_item: row.name || "",
          can_link: canLink
        };
      })
      .filter(row => Number(row.qty || row.planned_qty || 0) > 0);

    let warning = "";
    if (!canLink && so.name) {
      warning = `Sales Order ${so.name} is draft. Manufacturing documents can use its items, but they will not be linked until the Sales Order is submitted.`;
    } else if (canLink && !lines.length) {
      warning = `Sales Order ${so.name} has no pending manufacturable quantity.`;
    }

    return {
      sales_order: so.name || "",
      customer: so.customer || "",
      company: so.company || "",
      docstatus: Number(so.docstatus || 0),
      can_link: canLink,
      warning,
      lines
    };
  }

  function normalizeSalesOrderItems(rows, fallbackDate) {
    const out = [];
    (rows || []).forEach((row) => {
      const itemCode = String(row?.item_code || "").trim();
      const qty = Number(row?.qty || 0);
      const deliveryDate = row?.delivery_date || fallbackDate || frappe.datetime.now_date();
      const warehouse = row?.warehouse || row?.source_warehouse || "";
      if (!itemCode || qty <= 0) return;
      out.push({
        item_code: itemCode,
        qty: qty,
        delivery_date: deliveryDate,
        warehouse
      });
    });
    return out;
  }

  async function getSalesOrderSeed(seed) {
    const today = frappe.datetime.now_date();
    const base = Object.assign({
      company: "",
      customer: "",
      sales_order: "",
      item_code: "",
      qty: 1,
      schedule_date: today,
      delivery_date: today,
      items: []
    }, seed || {});

    if (!base.company && frappe.defaults?.get_default) {
      base.company = frappe.defaults.get_default("company") || "";
    }

    const hasExplicitItems = Array.isArray(base.items) && base.items.some(row => row?.item_code);
    if (base.sales_order && (!base.customer || !hasExplicitItems)) {
      try {
        const r = await frappe.call({
          method: "frappe.client.get",
          args: { doctype: "Sales Order", name: base.sales_order }
        });
        const so = r?.message || {};
        if (!base.customer) base.customer = so.customer || "";
        if (!base.company) base.company = so.company || base.company || "";
        if (!hasExplicitItems && Array.isArray(so.items) && so.items.length) {
          base.items = so.items.map(row => ({
            item_code: row.item_code || "",
            qty: Number(row.qty || 0),
            delivery_date: row.delivery_date || so.delivery_date || base.delivery_date || today,
            warehouse: row.warehouse || so.set_warehouse || base.source_warehouse || ""
          }));
        }
      } catch (e) {
        console.warn("Failed to load sales order seed", e);
      }
    }

    if ((!base.items || !base.items.length) && base.item_code) {
      base.items = [{
        item_code: base.item_code,
        qty: Number(base.qty || 1),
        delivery_date: base.delivery_date || base.schedule_date || today,
        warehouse: base.source_warehouse || ""
      }];
    }

    if (!base.items || !base.items.length) {
      base.items = [{
        item_code: "",
        qty: 1,
        delivery_date: base.delivery_date || base.schedule_date || today,
        warehouse: base.source_warehouse || ""
      }];
    }

    base.items = base.items.map(row => ({
      item_code: row.item_code || "",
      qty: Number(row.qty || 1),
      delivery_date: row.delivery_date || base.delivery_date || base.schedule_date || today,
      warehouse: row.warehouse || base.source_warehouse || ""
    }));

    return base;
  }

