  async function loadSalesOrderLinesIntoGrid(dialog, fieldname, rowMapper) {
    const salesOrder = dialog.get_value("sales_order");
    if (!salesOrder) {
      frappe.show_alert({ message: "Select a Sales Order first.", indicator: "orange" }, 4);
      return { can_link: false, warning: "Select a Sales Order first." };
    }

    const soSeed = await getSalesOrderManufacturingSeed(salesOrder, dialog.get_value("planned_start_date") || dialog.get_value("posting_date") || frappe.datetime.now_date());
    const rows = (soSeed.lines || []).map((row) => rowMapper(row, soSeed));
    const tableData = dialog.fields_dict[fieldname].df.data || [];
    tableData.splice(0, tableData.length, ...rows);
    dialog.fields_dict[fieldname].grid.refresh();
    if (soSeed.company && !dialog.get_value("company")) dialog.set_value("company", soSeed.company);
    if (soSeed.customer && dialog.fields_dict.customer && !dialog.get_value("customer")) dialog.set_value("customer", soSeed.customer);
    return soSeed;
  }

