            frappe.show_alert({ message: "Target Warehouse is required.", indicator: "orange" }, 4);
            return;
          }
          if (!rows.length) {
            frappe.show_alert({ message: "Add at least one valid Work Order row with Item, BOM, and Qty.", indicator: "orange" }, 5);
            return;
          }

          const createdNames = [];
          let jobCardCount = 0;
          try {
            for (const row of rows) {
              let doc = {
                doctype: "Work Order",
                company: values.company,
                production_item: row.item_code,
                bom_no: row.bom_no,
                qty: Number(row.qty || 0),
                planned_start_date: values.planned_start_date || frappe.datetime.now_datetime(),
                fg_warehouse: values.fg_warehouse,
                source_warehouse: values.source_warehouse || "",
                wip_warehouse: values.wip_warehouse || "",
                scrap_warehouse: values.scrap_warehouse || "",
                skip_transfer: values.skip_transfer ? 1 : 0,
                sales_order: row.sales_order || "",
                sales_order_item: row.sales_order_item || ""
              };
              doc = await insertDraftDoc(doc, `Creating Work Order draft for ${row.item_code}...`);
              if (values.submit_after_create) {
                doc = await submitDraftDoc(doc, `Submitting Work Order ${doc.name || row.item_code}...`);
                const jobCards = await getDocList("Job Card", { work_order: doc.name }, ["name"], 500);
                jobCardCount += jobCards.length;
              }
              const created = doc;
              if (created?.name) createdNames.push(created.name);
            }
            d.hide();
            frappe.show_alert({
              message: `${createdNames.length} ${values.submit_after_create ? "submitted" : "draft"} Work Order${createdNames.length === 1 ? "" : "s"} created${jobCardCount ? ` with ${jobCardCount} Job Card(s)` : ""}.`,
              indicator: "green"
            }, 6);
            if (createdNames[0]) {
              window.open(`/app/work-order/${encodeURIComponent(createdNames[0])}`, "_blank");
            }
            if (values.sales_order && !currentSoCanLink) {
              frappe.show_alert({
                message: "Selected Sales Order is draft, so created Work Orders were not linked to it.",
                indicator: "orange"
              }, 7);
            }
          } catch (e) {
            frappe.show_alert({ message: "Failed to create Work Order draft(s): " + (e.message || "Unknown error"), indicator: "red" }, 6);
          }
        }
      });

      d.fields_dict.help_html.$wrapper.html(
        `<div style="padding:10px;border:1px solid #ede9fe;border-radius:8px;background:#f5f3ff;color:#5b21b6;font-size:12px;">
          Required for Work Order: Company, Planned Start Date, Target Warehouse, and item rows with Item, BOM, and Qty.
          Source/WIP/Scrap warehouses are optional but recommended for controlled manufacturing flow.
          Submitted Sales Orders can be linked line-by-line; draft Sales Orders can only be used as a seed.
        </div>`
      );

      d.fields_dict.load_sales_order_items.$input.css({
        "background": "linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%)",
        "border": "none",
        "color": "#fff",
        "font-weight": "700",
        "border-radius": "8px",
        "padding": "8px 14px"
      });
      d.fields_dict.load_sales_order_items.$input.on("click", async () => {
        const soSeed = await loadSalesOrderLinesIntoGrid(d, "wo_items", (row, meta) => ({
          item_code: row.item_code || "",
          bom_no: row.bom_no || "",
          qty: Number(row.qty || 0),
          sales_order: meta.can_link ? (row.sales_order || meta.sales_order || "") : "",
          sales_order_item: meta.can_link ? (row.sales_order_item || "") : ""
        }));
        currentSoCanLink = !!soSeed.can_link;
        if (soSeed.warning) {
          frappe.show_alert({ message: soSeed.warning, indicator: soSeed.can_link ? "blue" : "orange" }, 7);
        }
      });

      d.show();
      if (seed.sales_order) {
        d.fields_dict.load_sales_order_items.$input.trigger("click");
      } else if (d.fields_dict.wo_items?.grid) {
        d.fields_dict.wo_items.grid.refresh();
      }
    } catch (e) {
      frappe.show_alert({ message: "Failed to open Work Order creator: " + (e.message || "Unknown error"), indicator: "red" }, 6);
    }
  }

  async function openWorkOrderStockEntryCreator(seedOverride, purpose) {
    const seed = await hydrateActionSeed(seedOverride);
    const workOrderName = seed.work_order || "";
    if (!workOrderName) {
      frappe.show_alert({ message: "Select or seed a Work Order first.", indicator: "orange" }, 5);
      return;
    }

    try {
      const wo = await getDoc("Work Order", workOrderName);
      const defaultQty = purpose === "Material Transfer for Manufacture"
        ? Math.max(Number(wo?.qty || 0) - Number(wo?.material_transferred_for_manufacturing || 0), 1)
        : purpose === "Manufacture"
          ? Math.max(Number(wo?.qty || 0) - Number(wo?.produced_qty || 0), 1)
          : 1;

      const buildTransferItemsFromWorkOrder = (transferQty, sourceWarehouse, targetWarehouse) => {
        const woQty = Math.max(Number(wo?.qty || 0), 1);
        const ratio = Math.max(Number(transferQty || 0), 0) / woQty;
        return (wo?.required_items || [])
          .map((row) => {
            const scaledRequiredQty = Number(row.required_qty || 0) * (ratio || 1);
            const alreadyTransferred = Number(row.transferred_qty || 0);
            const pendingQty = Math.max(scaledRequiredQty - Math.min(alreadyTransferred, scaledRequiredQty), 0);
            return {
              item_code: row.item_code || "",
              qty: pendingQty,
              stock_uom: row.stock_uom || "",
              s_warehouse: row.source_warehouse || sourceWarehouse || wo?.source_warehouse || "",
              t_warehouse: targetWarehouse || wo?.wip_warehouse || ""
            };
          })
          .filter((row) => row.item_code && Number(row.qty || 0) > 0);
      };

      const getStockEntrySeed = async (qtyValue, targetWarehouse) => {
        try {
          const r = await frappe.call({
            method: "erpnext.manufacturing.doctype.work_order.work_order.make_stock_entry",
            args: {
              work_order_id: workOrderName,
              purpose,
              qty: qtyValue,
              target_warehouse: targetWarehouse || ""
            },
            freeze: true,
            freeze_message: `Preparing ${purpose} entry...`
          });
          return r?.message || null;
        } catch (e) {
          return null;
        }
      };

      if (purpose === "Material Transfer for Manufacture") {
        const seedDoc = await getStockEntrySeed(defaultQty, wo?.wip_warehouse || "");
        const draftRows = Array.isArray(seedDoc?.items) && seedDoc.items.length
          ? seedDoc.items.map((row) => ({
              item_code: row.item_code || "",
              qty: Number(row.qty || 0),
              stock_uom: row.stock_uom || row.uom || "",
              s_warehouse: row.s_warehouse || row.from_warehouse || wo?.source_warehouse || "",
              t_warehouse: row.t_warehouse || row.to_warehouse || wo?.wip_warehouse || ""
            }))
          : buildTransferItemsFromWorkOrder(defaultQty, wo?.source_warehouse || "", wo?.wip_warehouse || "");

        const d = new frappe.ui.Dialog({
          title: `${purpose} - ${workOrderName}`,
          size: "extra-large",
          fields: [
            { fieldtype: "HTML", fieldname: "help_html" },
            { fieldtype: "Section Break" },
            { fieldtype: "Link", fieldname: "work_order", label: "Work Order", options: "Work Order", default: workOrderName, reqd: 1 },
            { fieldtype: "Column Break" },
            { fieldtype: "Float", fieldname: "qty", label: "FG Qty To Transfer", default: defaultQty, reqd: 1 },
            { fieldtype: "Column Break" },
            { fieldtype: "Button", fieldname: "load_items", label: "Load Items" },
            { fieldtype: "Section Break" },
            { fieldtype: "Link", fieldname: "source_warehouse", label: "Default Source Warehouse", options: "Warehouse", default: wo?.source_warehouse || "" },
            { fieldtype: "Column Break" },
            { fieldtype: "Link", fieldname: "target_warehouse", label: "WIP / Target Warehouse", options: "Warehouse", default: wo?.wip_warehouse || "", reqd: 1 },
            { fieldtype: "Column Break" },
            { fieldtype: "Check", fieldname: "submit_after_create", label: "Submit after create", default: 0 },
            { fieldtype: "Section Break" },
            {
              fieldtype: "Table",
              fieldname: "items",
              label: "Transfer Items",
              cannot_add_rows: false,
              in_place_edit: true,
              reqd: 1,
              data: draftRows,
              get_data: () => draftRows,
              fields: [
                { fieldtype: "Link", fieldname: "item_code", label: "Item", options: "Item", reqd: 1, in_list_view: 1 },
                { fieldtype: "Float", fieldname: "qty", label: "Qty", reqd: 1, in_list_view: 1 },
                { fieldtype: "Link", fieldname: "stock_uom", label: "UOM", options: "UOM", in_list_view: 1 },
                { fieldtype: "Link", fieldname: "s_warehouse", label: "From Warehouse", options: "Warehouse", reqd: 1, in_list_view: 1 },
                { fieldtype: "Link", fieldname: "t_warehouse", label: "To Warehouse", options: "Warehouse", reqd: 1, in_list_view: 1 }
              ]
            }
          ],
          primary_action_label: `Create ${purpose} Entry`,
          primary_action: async (values) => {
            const rows = (values.items || [])
              .map((row) => ({
                doctype: "Stock Entry Detail",
                item_code: String(row.item_code || "").trim(),
                qty: Number(row.qty || 0),
                s_warehouse: row.s_warehouse || values.source_warehouse || "",
                t_warehouse: row.t_warehouse || values.target_warehouse || "",
                uom: row.stock_uom || "",
                stock_uom: row.stock_uom || "",
                conversion_factor: 1
              }))
              .filter((row) => row.item_code && row.qty > 0 && row.s_warehouse && row.t_warehouse);

            if (!rows.length) {
              frappe.show_alert({ message: "Add at least one transfer item with item, qty, from warehouse, and to warehouse.", indicator: "orange" }, 5);
              return;
            }

            try {
              const seedDocNow = await getStockEntrySeed(values.qty, values.target_warehouse || "");
              const doc = Object.assign({}, seedDocNow || {
                doctype: "Stock Entry",
                purpose,
                stock_entry_type: purpose,
                company: wo?.company || seed.company || "",
                work_order: values.work_order,
                from_bom: 1,
                bom_no: wo?.bom_no || "",
                fg_completed_qty: values.qty || defaultQty
              });

              doc.doctype = "Stock Entry";
              doc.purpose = purpose;
              doc.stock_entry_type = purpose;
              doc.company = wo?.company || seed.company || "";
              doc.work_order = values.work_order;
              doc.from_bom = 1;
              doc.bom_no = wo?.bom_no || "";
              doc.fg_completed_qty = Number(values.qty || defaultQty);
              doc.from_warehouse = values.source_warehouse || "";
              doc.to_warehouse = values.target_warehouse || "";
              doc.items = rows;

              let stockEntry = await insertDraftDoc(doc, `Creating ${purpose} draft...`);
              if (values.submit_after_create) {
                stockEntry = await submitDraftDoc(stockEntry, `Submitting ${purpose} entry...`);
              }
              d.hide();
              frappe.show_alert({
                message: `${values.submit_after_create ? "Submitted" : "Draft"} ${purpose} entry ${stockEntry.name || ""} created.`,
                indicator: "green"
              }, 6);
              if (stockEntry.name) {
                window.open(`/app/stock-entry/${encodeURIComponent(stockEntry.name)}`, "_blank");
              }
            } catch (e) {
              frappe.show_alert({ message: `Failed to create ${purpose} entry: ` + (e.message || "Unknown error"), indicator: "red" }, 6);
            }
          }
        });

        d.fields_dict.help_html.$wrapper.html(
          `<div style="padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#f8fafc;color:#334155;font-size:12px;">
            <div><b>Basis:</b> Work Order ${escapeHtml(workOrderName)} | BOM ${escapeHtml(wo?.bom_no || "-")} | Material Request ${escapeHtml(wo?.material_request || "-")}</div>
            <div style="margin-top:4px;"><b>Transfer Against:</b> ${escapeHtml(wo?.transfer_material_against || "Work Order")} | <b>Skip Transfer:</b> ${wo?.skip_transfer ? "Yes" : "No"}</div>
            <div style="margin-top:6px;color:${wo?.transfer_material_against === "Job Card" ? "#b45309" : "#475569"};">
              ${wo?.transfer_material_against === "Job Card"
                ? "This Work Order is configured to transfer material against Job Card. Main Work Order transfer may not match your standard flow."
                : "Load Items will pull pending raw materials from the Work Order / BOM so you can adjust warehouses and quantities before posting."}
            </div>
          </div>`
        );

        d.fields_dict.load_items.$input.css({
          "background": "linear-gradient(135deg,#f59e0b 0%,#d97706 100%)",
          "border": "none",
          "color": "#fff",
          "font-weight": "700",
          "border-radius": "8px",
          "padding": "8px 14px"
        });

        d.fields_dict.load_items.$input.on("click", async () => {
          const qtyValue = Number(d.get_value("qty") || defaultQty);
          const sourceWarehouse = d.get_value("source_warehouse") || wo?.source_warehouse || "";
          const targetWarehouse = d.get_value("target_warehouse") || wo?.wip_warehouse || "";
          const freshSeed = await getStockEntrySeed(qtyValue, targetWarehouse);
          const rows = Array.isArray(freshSeed?.items) && freshSeed.items.length
            ? freshSeed.items.map((row) => ({
                item_code: row.item_code || "",
                qty: Number(row.qty || 0),
                stock_uom: row.stock_uom || row.uom || "",
                s_warehouse: row.s_warehouse || sourceWarehouse,
                t_warehouse: row.t_warehouse || targetWarehouse
              }))
            : buildTransferItemsFromWorkOrder(qtyValue, sourceWarehouse, targetWarehouse);
          const tableData = d.fields_dict.items.df.data || [];
          tableData.splice(0, tableData.length, ...rows);
          d.fields_dict.items.grid.refresh();
        });

        d.show();
        if (d.fields_dict.items?.grid) {
          d.fields_dict.items.grid.refresh();
        }
        return;
      }

      const d = new frappe.ui.Dialog({
        title: `${purpose} - ${workOrderName}`,
        fields: [
          { fieldtype: "HTML", fieldname: "help_html" },
          { fieldtype: "Section Break" },
          { fieldtype: "Link", fieldname: "work_order", label: "Work Order", options: "Work Order", default: workOrderName, reqd: 1 },
          { fieldtype: "Column Break" },
          { fieldtype: "Float", fieldname: "qty", label: "Qty", default: defaultQty, reqd: 1 },
          { fieldtype: "Column Break" },
          { fieldtype: "Check", fieldname: "submit_after_create", label: "Submit after create", default: 0 },
          { fieldtype: "Section Break" },
          { fieldtype: "Link", fieldname: "target_warehouse", label: purpose === "Disassemble" ? "Return To Warehouse" : "Target Warehouse", options: "Warehouse", default: purpose === "Disassemble" ? (seed.source_warehouse || wo?.source_warehouse || "") : "" }
        ],
        primary_action_label: `Create ${purpose} Entry`,
        primary_action: async (values) => {
          try {
            const r = await frappe.call({
              method: "erpnext.manufacturing.doctype.work_order.work_order.make_stock_entry",
              args: {
                work_order_id: values.work_order,
                purpose,
                qty: values.qty,
                target_warehouse: values.target_warehouse || ""
              },
              freeze: true,
              freeze_message: `Preparing ${purpose} entry...`
            });
            let stockEntry = await insertDraftDoc(r?.message || {}, `Creating ${purpose} draft...`);
            if (values.submit_after_create) {
              stockEntry = await submitDraftDoc(stockEntry, `Submitting ${purpose} entry...`);
            }
            d.hide();
            frappe.show_alert({
              message: `${values.submit_after_create ? "Submitted" : "Draft"} ${purpose} entry ${stockEntry.name || ""} created.`,
              indicator: "green"
            }, 6);
            if (stockEntry.name) {
              window.open(`/app/stock-entry/${encodeURIComponent(stockEntry.name)}`, "_blank");
            }
          } catch (e) {
            frappe.show_alert({ message: `Failed to create ${purpose} entry: ` + (e.message || "Unknown error"), indicator: "red" }, 6);
          }
        }
      });

      d.fields_dict.help_html.$wrapper.html(
        `<div style="padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#f8fafc;color:#334155;font-size:12px;">
          ${purpose === "Material Transfer for Manufacture"
            ? "Use this after submitted Work Orders to move raw material into WIP."
            : purpose === "Manufacture"
              ? "Use this after Job Card progress to record finished goods and consumption."
              : "Use this to return or disassemble material from finished goods back to source warehouse."}
        </div>`
      );

      if (purpose !== "Disassemble") {
        d.set_df_property("target_warehouse", "hidden", 1);
      }

      d.show();
    } catch (e) {
      frappe.show_alert({ message: `Failed to open ${purpose} entry creator: ` + (e.message || "Unknown error"), indicator: "red" }, 6);
    }
  }

  async function openProductionPlanMaterialRequestCreator(productionPlanName) {
    if (!productionPlanName) {
      frappe.show_alert({ message: "Select a Production Plan first.", indicator: "orange" }, 4);
      return;
    }
    try {
      const pp = await getDoc("Production Plan", productionPlanName);
      if (!pp) {
        frappe.show_alert({ message: "Production Plan not found.", indicator: "orange" }, 4);
        return;
      }
      const d = new frappe.ui.Dialog({
        title: `Material Request - ${productionPlanName}`,
        size: "large",
        fields: [
          { fieldtype: "HTML", fieldname: "help_html" },
          { fieldtype: "Section Break" },
          { fieldtype: "Link", fieldname: "company", label: "Company", options: "Company", default: pp.company || "", read_only: 1 },
          { fieldtype: "Column Break" },
          { fieldtype: "Link", fieldname: "production_plan", label: "Production Plan", options: "Production Plan", default: pp.name || "", read_only: 1 },
          { fieldtype: "Column Break" },
          { fieldtype: "Link", fieldname: "for_warehouse", label: "For Warehouse", options: "Warehouse", default: pp.for_warehouse || pp.warehouse || "", reqd: 1 },
          { fieldtype: "Section Break" },
          { fieldtype: "Select", fieldname: "material_request_type", label: "Purpose", options: "Purchase\nMaterial Transfer\nMaterial Issue\nManufacture\nCustomer Provided", default: "Purchase", reqd: 1 },
          { fieldtype: "Column Break" },
          { fieldtype: "Link", fieldname: "customer", label: "Customer", options: "Customer", default: pp.customer || "" },
          { fieldtype: "Column Break" },
          { fieldtype: "Date", fieldname: "schedule_date", label: "Required By", default: frappe.datetime.now_date(), reqd: 1 },
          { fieldtype: "Section Break" },
          { fieldtype: "Check", fieldname: "ignore_existing_ordered_qty", label: "Ignore Existing Projected Qty", default: pp.ignore_existing_ordered_qty ? 1 : 0 },
          { fieldtype: "Column Break" },
          { fieldtype: "Check", fieldname: "include_safety_stock", label: "Include Safety Stock", default: pp.include_safety_stock ? 1 : 0 },
          { fieldtype: "Column Break" },
          { fieldtype: "Check", fieldname: "submit_material_request", label: "Submit after create", default: 0 }
        ],
        primary_action_label: "Create Material Request",
        primary_action: async (values) => {
          try {
            const runtimeDoc = Object.assign({}, pp, {
              for_warehouse: values.for_warehouse,
              ignore_existing_ordered_qty: values.ignore_existing_ordered_qty ? 1 : 0,
              include_safety_stock: values.include_safety_stock ? 1 : 0,
              submit_material_request: values.submit_material_request ? 1 : 0,
              mr_items: []
            });
            const itemsResp = await frappe.call({
              method: "erpnext.manufacturing.doctype.production_plan.production_plan.get_items_for_material_requests",
              args: {
                doc: runtimeDoc,
                warehouses: values.for_warehouse ? [{ warehouse: values.for_warehouse }] : []
              },
              freeze: true,
              freeze_message: "Getting Material Request items..."
            });
            const mrItems = itemsResp?.message || [];
            if (!mrItems.length) {
              frappe.show_alert({ message: "No Material Request items found for this Production Plan.", indicator: "orange" }, 6);
              return;
            }
            runtimeDoc.customer = values.customer || pp.customer || "";
            runtimeDoc.mr_items = mrItems.map((row) => Object.assign({
              doctype: "Material Request Plan Item",
              material_request_type: values.material_request_type || row.material_request_type || "Purchase",
              schedule_date: values.schedule_date || row.schedule_date || frappe.datetime.now_date()
            }, row, {
              material_request_type: values.material_request_type || row.material_request_type || "Purchase",
              schedule_date: values.schedule_date || row.schedule_date || frappe.datetime.now_date()
            }));
            await frappe.call({
              method: "frappe.handler.run_doc_method",
              args: {
                docs: JSON.stringify(runtimeDoc),
                method: "make_material_request"
              },
              freeze: true,
              freeze_message: "Creating Material Request..."
            });
            d.hide();
            frappe.show_alert({ message: `Material Request created from ${productionPlanName}.`, indicator: "green" }, 6);
          } catch (e) {
            frappe.show_alert({ message: "Failed to create Material Request: " + (e.message || "Unknown error"), indicator: "red" }, 6);
          }
        }
      });
      d.fields_dict.help_html.$wrapper.html(
        `<div style="padding:10px;border:1px solid #dbeafe;border-radius:8px;background:#eff6ff;color:#1d4ed8;font-size:12px;">
          Material Request is created from Production Plan items, not from a separate generic item row. Choose the warehouse and purpose, then this will pull raw materials from the Production Plan and create the Material Request correctly.
        </div>`
      );
      d.show();
    } catch (e) {
      frappe.show_alert({ message: "Failed to open Material Request dialog: " + (e.message || "Unknown error"), indicator: "red" }, 6);
    }
  }

  async function openExistingManufacturingManager(seedOverride) {
    const seed = await hydrateActionSeed(seedOverride);
    const d = new frappe.ui.Dialog({
      title: "Existing Manufacturing Documents",
      size: "extra-large",
      fields: [
        { fieldtype: "Section Break" },
        { fieldtype: "Link", fieldname: "company", label: "Company", options: "Company", default: seed.company || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Link", fieldname: "production_plan", label: "Production Plan", options: "Production Plan", default: seed.production_plan || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Link", fieldname: "work_order", label: "Work Order", options: "Work Order", default: seed.work_order || "" },
        { fieldtype: "Section Break" },
        { fieldtype: "Link", fieldname: "sales_order", label: "Sales Order", options: "Sales Order", default: seed.sales_order || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Button", fieldname: "load_btn", label: "Load Documents" },
        { fieldtype: "Section Break" },
        { fieldtype: "HTML", fieldname: "body_html" }
      ]
    });

    const badge = (text, bg, color) =>
      `<span style="display:inline-block;padding:3px 8px;border-radius:999px;background:${bg};color:${color};font-weight:700;font-size:11px;">${escapeHtml(text || "-")}</span>`;

    const statusBadge = (status, docstatus) => {
      if (Number(docstatus || 0) === 0) return badge(status || "Draft", "#fef3c7", "#92400e");
      if (String(status || "").toLowerCase().includes("completed")) return badge(status, "#dcfce7", "#166534");
      if (String(status || "").toLowerCase().includes("progress")) return badge(status, "#dbeafe", "#1d4ed8");
      return badge(status || "Submitted", "#e5e7eb", "#334155");
    };

    const buildActionButton = (label, attrs, colors) => {
      return `<button ${attrs} style="padding:6px 10px;border:none;border-radius:8px;background:${colors.bg};color:${colors.text};font-weight:700;cursor:pointer;">${label}</button>`;
    };

    const loadData = async () => {
      d.fields_dict.body_html.$wrapper.html('<div style="padding:12px;color:#64748b;">Loading...</div>');
      const v = d.get_values() || {};

      const ppFilters = {};
      if (v.company) ppFilters.company = v.company;
      if (v.production_plan) ppFilters.name = v.production_plan;

      const woFilters = {};
      if (v.company) woFilters.company = v.company;
      if (v.work_order) woFilters.name = v.work_order;
      if (v.sales_order) woFilters.sales_order = v.sales_order;
      if (v.production_plan) woFilters.production_plan = v.production_plan;

      const ppRows = await getDocList(
        "Production Plan",
        ppFilters,
        ["name", "status", "docstatus", "company", "posting_date", "modified"],
        20
      );

      const woRows = await getDocList(
        "Work Order",
        woFilters,
        ["name", "status", "docstatus", "production_item", "qty", "produced_qty", "sales_order", "production_plan", "skip_transfer", "transfer_material_against", "modified"],
        50
      );

      const woNames = [...new Set(woRows.map(x => x.name).filter(Boolean))];
      let jcRows = [];
      if (v.work_order) {
        jcRows = await getDocList(
          "Job Card",
          { work_order: v.work_order },
          ["name", "status", "docstatus", "work_order", "operation", "for_quantity", "total_completed_qty", "modified"],
          100
        );
      } else if (woNames.length) {
        jcRows = await getDocList(
          "Job Card",
          [["Job Card", "work_order", "in", woNames]],
          ["name", "status", "docstatus", "work_order", "operation", "for_quantity", "total_completed_qty", "modified"],
          200
        );
      }

      const ppHtml = ppRows.length ? `
        <div style="margin:0 0 8px;font-weight:800;color:#1e293b;">Production Plans</div>
        <div style="overflow:auto;border:1px solid #e5e7eb;border-radius:10px;">
          <table style="width:100%;border-collapse:collapse;font-size:12px;">
