                  <td style="padding:8px;border-top:1px solid #f1f5f9;">${statusBadge(row.status, row.docstatus)}</td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;">${escapeHtml(row.posting_date || "")}</td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;display:flex;gap:6px;flex-wrap:wrap;">
                    ${Number(row.docstatus || 0) === 0 ? buildActionButton("Submit", `data-pp-submit="${escapeHtml(row.name || "")}"`, { bg: "#2563eb", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 1 ? buildActionButton("Start / Create WO", `data-pp-start="${escapeHtml(row.name || "")}"`, { bg: "#16a34a", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 0 ? buildActionButton("Submit + Start", `data-pp-submit-start="${escapeHtml(row.name || "")}"`, { bg: "#7c3aed", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 1 ? buildActionButton("Material Request", `data-pp-mr="${escapeHtml(row.name || "")}"`, { bg: "#0f766e", text: "#fff" }) : ""}
                  </td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      ` : '<div style="padding:12px;color:#64748b;">No Production Plans found for current filters.</div>';

      const woHtml = woRows.length ? `
        <div style="margin:16px 0 8px;font-weight:800;color:#1e293b;">Work Orders</div>
        <div style="overflow:auto;border:1px solid #e5e7eb;border-radius:10px;">
          <table style="width:100%;border-collapse:collapse;font-size:12px;">
            <thead>
              <tr>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Name</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Status</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Item</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Qty</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Actions</th>
              </tr>
            </thead>
            <tbody>
              ${woRows.map(row => `
                <tr>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;"><a href="/app/work-order/${encodeURIComponent(row.name || "")}" target="_blank" style="color:#1d4ed8;font-weight:700;text-decoration:none;">${escapeHtml(row.name || "")}</a></td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;">${statusBadge(row.status, row.docstatus)}</td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;">${escapeHtml(row.production_item || "")}</td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;">${fmt(row.produced_qty || 0)} / ${fmt(row.qty || 0)}</td>
                  <td style="padding:8px;border-top:1px solid #f1f5f9;display:flex;gap:6px;flex-wrap:wrap;">
                    ${Number(row.docstatus || 0) === 0 ? buildActionButton("Submit", `data-wo-submit="${escapeHtml(row.name || "")}"`, { bg: "#2563eb", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 1 && String(row.status || "").toLowerCase() === "not started" ? buildActionButton("Next Step", `data-wo-start="${escapeHtml(row.name || "")}" data-wo-skip="${row.skip_transfer ? "1" : "0"}" data-wo-transfer="${escapeHtml(row.transfer_material_against || "")}"`, { bg: "#16a34a", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 1 ? buildActionButton("Material Transfer", `data-wo-transfer-entry="${escapeHtml(row.name || "")}"`, { bg: "#f59e0b", text: "#fff" }) : ""}
                    ${Number(row.docstatus || 0) === 1 ? buildActionButton("Manufacture", `data-wo-manufacture="${escapeHtml(row.name || "")}"`, { bg: "#0ea5e9", text: "#fff" }) : ""}
