            </tbody>
          </table>
        </div>
      ` : '<div style="padding:12px;color:#64748b;">No Work Orders found for current filters.</div>';

      const jcHtml = jcRows.length ? `
        <div style="margin:16px 0 8px;font-weight:800;color:#1e293b;">Job Cards</div>
        <div style="overflow:auto;border:1px solid #e5e7eb;border-radius:10px;">
          <table style="width:100%;border-collapse:collapse;font-size:12px;">
            <thead>
              <tr>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Name</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Status</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Work Order</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Operation</th>
                <th style="text-align:left;padding:8px;background:#f8fafc;">Actions</th>
              </tr>
            </thead>
            <tbody>
              ${jcRows.map(row => {
                const lowerStatus = String(row.status || "").toLowerCase();
                return `
                  <tr>
                    <td style="padding:8px;border-top:1px solid #f1f5f9;"><a href="/app/job-card/${encodeURIComponent(row.name || "")}" target="_blank" style="color:#1d4ed8;font-weight:700;text-decoration:none;">${escapeHtml(row.name || "")}</a></td>
                    <td style="padding:8px;border-top:1px solid #f1f5f9;">${statusBadge(row.status, row.docstatus)}</td>
                    <td style="padding:8px;border-top:1px solid #f1f5f9;">${escapeHtml(row.work_order || "")}</td>
                    <td style="padding:8px;border-top:1px solid #f1f5f9;">${escapeHtml(row.operation || "")}</td>
                    <td style="padding:8px;border-top:1px solid #f1f5f9;display:flex;gap:6px;flex-wrap:wrap;">
                      ${(Number(row.docstatus || 0) === 0 && (lowerStatus === "open" || lowerStatus === "material transferred")) ? buildActionButton("Start Job", `data-jc-start="${escapeHtml(row.name || "")}"`, { bg: "#16a34a", text: "#fff" }) : ""}
                      ${(Number(row.docstatus || 0) === 0 && lowerStatus === "work in progress") ? buildActionButton("Pause Job", `data-jc-partial="${escapeHtml(row.name || "")}"`, { bg: "#f59e0b", text: "#fff" }) : ""}
                      ${(Number(row.docstatus || 0) === 0 && lowerStatus === "work in progress") ? buildActionButton("Complete Job", `data-jc-complete="${escapeHtml(row.name || "")}"`, { bg: "#2563eb", text: "#fff" }) : ""}
                    </td>
                  </tr>
                `;
              }).join("")}
            </tbody>
          </table>
        </div>
      ` : '<div style="padding:12px;color:#64748b;">No Job Cards found for current filters.</div>';

      d.fields_dict.body_html.$wrapper.html(`
        <div style="padding:4px;">
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;color:#475569;font-size:12px;margin-bottom:12px;">
            Draft Production Plans can be submitted here. "Start" for Production Plan means create Work Orders.
            Draft Work Orders can be submitted here. "Next Step" for Work Order opens the correct next action based on transfer settings.
            Open Job Cards can be started here; Work In Progress Job Cards can be updated or completed.
          </div>
          ${ppHtml}
          ${woHtml}
          ${jcHtml}
        </div>
      `);

      const root = d.fields_dict.body_html.$wrapper;

      root.find("[data-pp-submit]").on("click", async function() {
        const name = this.getAttribute("data-pp-submit");
        await submitExistingDoc("Production Plan", name);
        frappe.show_alert({ message: `Production Plan ${name} submitted.`, indicator: "green" }, 5);
        loadData();
      });

      root.find("[data-pp-start]").on("click", async function() {
        const name = this.getAttribute("data-pp-start");
        await runExistingDocMethod("Production Plan", name, "make_work_order", {}, "Creating Work Orders...");
        frappe.show_alert({ message: `Work Orders created from ${name}.`, indicator: "green" }, 5);
        loadData();
      });

      root.find("[data-pp-submit-start]").on("click", async function() {
        const name = this.getAttribute("data-pp-submit-start");
        await submitExistingDoc("Production Plan", name);
        await runExistingDocMethod("Production Plan", name, "make_work_order", {}, "Creating Work Orders...");
        frappe.show_alert({ message: `Production Plan ${name} submitted and started.`, indicator: "green" }, 5);
        loadData();
      });

      root.find("[data-pp-mr]").on("click", function() {
        const name = this.getAttribute("data-pp-mr");
        d.hide();
        openProductionPlanMaterialRequestCreator(name);
      });

      root.find("[data-wo-submit]").on("click", async function() {
        const name = this.getAttribute("data-wo-submit");
        await submitExistingDoc("Work Order", name);
        frappe.show_alert({ message: `Work Order ${name} submitted.`, indicator: "green" }, 5);
        loadData();
      });

      root.find("[data-wo-start]").on("click", async function() {
        const name = this.getAttribute("data-wo-start");
        const skip = this.getAttribute("data-wo-skip") === "1";
        const transferAgainst = this.getAttribute("data-wo-transfer") || "";
        d.hide();
        if (!skip && transferAgainst !== "Job Card") {
          openWorkOrderStockEntryCreator({ work_order: name }, "Material Transfer for Manufacture");
          return;
        }
        const latestJc = (await getDocList("Job Card", { work_order: name }, ["name", "status", "docstatus"], 1))[0];
        if (latestJc?.name) {
          startJobCard(latestJc.name);
        } else {
          frappe.show_alert({ message: `No Job Card found for ${name}.`, indicator: "orange" }, 5);
        }
      });

      root.find("[data-wo-transfer-entry]").on("click", function() {
        const name = this.getAttribute("data-wo-transfer-entry");
        d.hide();
        openWorkOrderStockEntryCreator({ work_order: name }, "Material Transfer for Manufacture");
      });

      root.find("[data-wo-manufacture]").on("click", function() {
        const name = this.getAttribute("data-wo-manufacture");
        d.hide();
        openWorkOrderStockEntryCreator({ work_order: name }, "Manufacture");
      });

      root.find("[data-jc-start]").on("click", function() {
        const name = this.getAttribute("data-jc-start");
        d.hide();
        startJobCard(name);
      });
      root.find("[data-jc-partial]").on("click", function() {
        const name = this.getAttribute("data-jc-partial");
        d.hide();
        partialJobCard(name);
      });
      root.find("[data-jc-complete]").on("click", function() {
        const name = this.getAttribute("data-jc-complete");
        d.hide();
        completeJobCard(name);
      });
    };

    d.fields_dict.load_btn.$input.css({
      "background": "linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%)",
      "border": "none",
      "color": "#fff",
      "font-weight": "700",
      "border-radius": "8px",
      "padding": "8px 14px"
    });
    d.fields_dict.load_btn.$input.on("click", loadData);
    d.show();
    loadData();
  }

  async function openManufacturingControlCenter(seedOverride) {
    const seed = await hydrateActionSeed(seedOverride);
    const d = new frappe.ui.Dialog({
      title: "Manufacturing Control Center",
      size: "extra-large",
      fields: [{ fieldtype: "HTML", fieldname: "body" }]
    });

    const html = `
      <div style="display:grid;gap:16px;">
        <div style="display:grid;grid-template-columns:repeat(5,minmax(140px,1fr));gap:10px;">
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;"><div style="font-size:11px;color:#64748b;">Company</div><div style="font-weight:800;color:#1e293b;">${escapeHtml(seed.company || "-")}</div></div>
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;"><div style="font-size:11px;color:#64748b;">Sales Order</div><div style="font-weight:800;color:#1e293b;">${escapeHtml(seed.sales_order || "-")}</div></div>
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;"><div style="font-size:11px;color:#64748b;">Production Plan</div><div style="font-weight:800;color:#1e293b;">${escapeHtml(seed.production_plan || "-")}</div></div>
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;"><div style="font-size:11px;color:#64748b;">Work Order</div><div style="font-weight:800;color:#1e293b;">${escapeHtml(seed.work_order || "-")}</div></div>
          <div style="padding:10px;border:1px solid #e5e7eb;border-radius:10px;background:#f8fafc;"><div style="font-size:11px;color:#64748b;">Item</div><div style="font-weight:800;color:#1e293b;">${escapeHtml(seed.item_code || "-")}</div></div>
        </div>
        <div style="padding:12px;border:1px solid #dbeafe;border-radius:12px;background:#eff6ff;color:#1d4ed8;font-size:12px;">
          Recommended flow: Sales Order -> Production Plan -> Submit Plan -> Material Request if needed -> Create/Submit Work Order -> Material Transfer -> Start/Pause/Complete Job Cards -> Manufacture/Return Material.
        </div>
        <div id="mcc_stage_panel" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;">
          <div style="padding:12px;border:1px solid #e5e7eb;border-radius:12px;background:#f8fafc;color:#64748b;">Loading stage status...</div>
        </div>
        <div id="mcc_warning_panel"></div>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;">
          <button id="mcc_create_so" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#16a34a 0%,#15803d 100%);color:#fff;font-weight:800;cursor:pointer;">Create Sales Order</button>
          <button id="mcc_create_pp" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%);color:#fff;font-weight:800;cursor:pointer;">Create Production Plan</button>
          <button id="mcc_create_wo" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#7c3aed 0%,#6d28d9 100%);color:#fff;font-weight:800;cursor:pointer;">Create Work Order</button>
          <button id="mcc_manage_existing" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#475569 0%,#334155 100%);color:#fff;font-weight:800;cursor:pointer;">Manage Existing Docs</button>
          <button id="mcc_transfer" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);color:#fff;font-weight:800;cursor:pointer;">Material Transfer</button>
          <button id="mcc_manufacture" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#2563eb 0%,#1d4ed8 100%);color:#fff;font-weight:800;cursor:pointer;">Manufacture Entry</button>
          <button id="mcc_delivery_note" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#0891b2 0%,#0f766e 100%);color:#fff;font-weight:800;cursor:pointer;">Create Delivery Note</button>
          <button id="mcc_return" style="padding:12px 14px;border:none;border-radius:10px;background:linear-gradient(135deg,#334155 0%,#1e293b 100%);color:#fff;font-weight:800;cursor:pointer;">Return / Disassemble</button>
          <button id="mcc_so_board" style="padding:12px 14px;border:none;border-radius:10px;background:#f8fafc;color:#334155;font-weight:800;cursor:pointer;border:1px solid #cbd5e1;">SO Status Board</button>
          <button id="mcc_open_docs" style="padding:12px 14px;border:none;border-radius:10px;background:#f8fafc;color:#334155;font-weight:800;cursor:pointer;border:1px solid #cbd5e1;">Open Current Documents</button>
        </div>
        <div style="padding:12px;border:1px solid #e5e7eb;border-radius:12px;background:#fff;color:#475569;font-size:12px;">
          Job Card controls stay on each live card: Start Job, Pause Job, Complete Job. Employee selection is required before timer updates or production posting.
        </div>
      </div>
    `;

    d.fields_dict.body.$wrapper.html(html);
    d.show();

    const root = d.fields_dict.body.$wrapper;
    root.find("#mcc_create_so").on("click", () => { d.hide(); openSalesOrderCreator(seed); });
    root.find("#mcc_create_pp").on("click", () => { d.hide(); openProductionPlanCreator(seed); });
    root.find("#mcc_create_wo").on("click", () => { d.hide(); openWorkOrderCreator(seed); });
    root.find("#mcc_manage_existing").on("click", () => { d.hide(); openExistingManufacturingManager(seed); });
    root.find("#mcc_transfer").on("click", () => { d.hide(); openWorkOrderStockEntryCreator(seed, "Material Transfer for Manufacture"); });
    root.find("#mcc_manufacture").on("click", () => { d.hide(); openWorkOrderStockEntryCreator(seed, "Manufacture"); });
    root.find("#mcc_delivery_note").on("click", () => { d.hide(); openDeliveryNoteCreator(seed); });
    root.find("#mcc_return").on("click", () => { d.hide(); openWorkOrderStockEntryCreator(seed, "Disassemble"); });
    root.find("#mcc_so_board").on("click", () => { d.hide(); window.openSalesOrderStatusBoard(); });
    root.find("#mcc_open_docs").on("click", () => {
      let opened = 0;
      if (seed.sales_order) window.open(`/app/sales-order/${encodeURIComponent(seed.sales_order)}`, "_blank");
      if (seed.sales_order) opened++;
      if (seed.production_plan) window.open(`/app/production-plan/${encodeURIComponent(seed.production_plan)}`, "_blank");
      if (seed.production_plan) opened++;
      if (seed.work_order) window.open(`/app/work-order/${encodeURIComponent(seed.work_order)}`, "_blank");
      if (seed.work_order) opened++;
      if (!opened) {
        frappe.show_alert({ message: "No current Sales Order, Production Plan, or Work Order found.", indicator: "orange" }, 5);
      }
    });

    const stagePanel = root.find("#mcc_stage_panel");
    const warningPanel = root.find("#mcc_warning_panel");
    try {
      const snapshot = await getManufacturingControlSnapshot(seed);
      const soLabel = snapshot.soRow
        ? `${snapshot.soRow.status || "-"} / ${snapshot.soRow.delivery_status || "-"}`
        : "No Sales Order";
      const ppLabel = snapshot.ppRows.length
        ? snapshot.ppRows.map((row) => row.status || (Number(row.docstatus || 0) === 1 ? "Submitted" : "Draft")).join(", ")
        : "No Production Plan";
      const woOpen = snapshot.woRows.filter((row) => String(row.status || "").toLowerCase() !== "completed").length;
      const transferPct = snapshot.metrics.woQty > 0 ? `${((snapshot.metrics.transferredQty / snapshot.metrics.woQty) * 100).toFixed(1)}%` : "0.0%";
      const manufacturePct = snapshot.metrics.woQty > 0 ? `${((snapshot.metrics.producedQty / snapshot.metrics.woQty) * 100).toFixed(1)}%` : "0.0%";

      stagePanel.html(`
        ${renderStageCard("Sales Order", seed.sales_order || "-", soLabel, { bg: "#eef2ff", border: "#c7d2fe", text: "#3730a3", sub: "#6366f1" })}
        ${renderStageCard("Production Plan", seed.production_plan || "-", ppLabel, { bg: "#ecfeff", border: "#a5f3fc", text: "#155e75", sub: "#0891b2" })}
        ${renderStageCard("Work Orders", `${snapshot.woRows.length}`, `${woOpen} open / in process`, { bg: "#f5f3ff", border: "#ddd6fe", text: "#5b21b6", sub: "#7c3aed" })}
        ${renderStageCard("Material Transfer", transferPct, `${snapshot.metrics.transferEntries} transfer entries`, { bg: "#fffbeb", border: "#fde68a", text: "#92400e", sub: "#d97706" })}
        ${renderStageCard("Job Cards", `${snapshot.metrics.jcCompleted}/${snapshot.metrics.jcTotal}`, "completed / total", { bg: "#fff7ed", border: "#fdba74", text: "#9a3412", sub: "#f97316" })}
        ${renderStageCard("Manufacture", manufacturePct, `${snapshot.metrics.manufactureEntries} manufacture entries`, { bg: "#eff6ff", border: "#bfdbfe", text: "#1d4ed8", sub: "#3b82f6" })}
        ${renderStageCard("Delivery", `${snapshot.metrics.deliveryCount}`, snapshot.soRow ? `${Number(snapshot.soRow.per_delivered || 0).toFixed(1)}% delivered` : "No Delivery Note", { bg: "#f0fdf4", border: "#bbf7d0", text: "#166534", sub: "#16a34a" })}
      `);

      if (snapshot.warnings.length) {
        warningPanel.html(`
          <div style="padding:12px;border:1px solid #fed7aa;border-radius:12px;background:#fff7ed;color:#9a3412;font-size:12px;">
            <div style="font-weight:800;margin-bottom:6px;">Validation Notes</div>
            ${snapshot.warnings.map((row) => `<div style="margin:4px 0;">• ${escapeHtml(row)}</div>`).join("")}
          </div>
        `);
      } else {
        warningPanel.html(`
          <div style="padding:12px;border:1px solid #bbf7d0;border-radius:12px;background:#f0fdf4;color:#166534;font-size:12px;">
            Current context looks ready for the next manufacturing step.
          </div>
        `);
      }
    } catch (e) {
      stagePanel.html('<div style="padding:12px;border:1px solid #fecaca;border-radius:12px;background:#fef2f2;color:#b91c1c;">Failed to load manufacturing stage status.</div>');
    }
  }

  function openActionCenter(seed) {
    try {
    const d = new frappe.ui.Dialog({
      title: "Action Center",
      fields: [
        { fieldtype: "HTML", fieldname: "action_help" },
        { fieldtype: "Section Break" },
        { fieldtype: "Select", fieldname: "action_type", label: "Action", reqd: 1, options: [
          "Create Sales Order",
          "Create Production Plan",
          "Create Work Order",
          "Create Material Request (Purchase)",
          "Create Material Request (Material Transfer)",
          "Create Purchase Order",
          "Create Stock Entry",
          "Open Sales Order",
          "Open Production Plan",
          "Open Work Order"
        ].join("\n"), default: seed.action_type || "Create Production Plan" },
        { fieldtype: "Column Break" },
        { fieldtype: "Link", fieldname: "company", label: "Company", options: "Company", default: seed.company || "" },
        { fieldtype: "Link", fieldname: "customer", label: "Customer", options: "Customer", default: seed.customer || "" },
