      ],
      primary_action_label: "Run Action",
      primary_action: (v) => {
        const actionType = v.action_type || "";
        if (actionType === "Open Sales Order") {
          if (!v.sales_order) return frappe.show_alert({ message: "No Sales Order to open.", indicator: "orange" }, 4);
          window.open(`/app/sales-order/${encodeURIComponent(v.sales_order)}`, "_blank");
          return;
        }
        if (actionType === "Open Production Plan") {
          if (!v.production_plan) return frappe.show_alert({ message: "No Production Plan to open.", indicator: "orange" }, 4);
          window.open(`/app/production-plan/${encodeURIComponent(v.production_plan)}`, "_blank");
          return;
        }
        if (actionType === "Open Work Order") {
          if (!v.work_order) return frappe.show_alert({ message: "No Work Order to open.", indicator: "orange" }, 4);
          window.open(`/app/work-order/${encodeURIComponent(v.work_order)}`, "_blank");
          return;
        }

        if (actionType === "Create Sales Order") {
          d.hide();
          window.openSalesOrderCreator({
            company: v.company || seed.company || "",
            customer: v.customer || seed.customer || "",
            sales_order: v.sales_order || seed.sales_order || "",
            item_code: v.item_code || seed.item_code || "",
            qty: Number(v.qty || seed.qty || 1),
            schedule_date: v.schedule_date || frappe.datetime.now_date(),
            delivery_date: v.schedule_date || frappe.datetime.now_date()
          });
          return;
        } else if (actionType === "Create Production Plan") {
          d.hide();
          window.openProductionPlanCreator({
            company: v.company || seed.company || "",
            sales_order: v.sales_order || seed.sales_order || "",
            item_code: v.item_code || seed.item_code || "",
            bom_no: v.bom_no || seed.bom_no || "",
            stock_uom: seed.stock_uom || "",
            planned_qty: Number(v.qty || seed.qty || 1),
            qty: Number(v.qty || seed.qty || 1),
            schedule_date: v.schedule_date || frappe.datetime.now_datetime(),
            target_warehouse: v.target_warehouse || seed.target_warehouse || ""
          });
          return;
        } else if (actionType === "Create Work Order") {
          d.hide();
          window.openWorkOrderCreator({
            company: v.company || seed.company || "",
            sales_order: v.sales_order || seed.sales_order || "",
            item_code: v.item_code || seed.item_code || "",
            bom_no: v.bom_no || seed.bom_no || "",
            qty: Number(v.qty || seed.qty || 1),
            schedule_date: v.schedule_date || frappe.datetime.now_datetime(),
            source_warehouse: v.source_warehouse || seed.source_warehouse || "",
            wip_warehouse: v.wip_warehouse || seed.wip_warehouse || "",
            target_warehouse: v.target_warehouse || seed.target_warehouse || "",
            scrap_warehouse: v.scrap_warehouse || seed.scrap_warehouse || ""
          });
          return;
        } else if (actionType === "Create Material Request (Purchase)") {
          openDocWithSeed("Material Request", (doc) => {
            doc.material_request_type = "Purchase";
            doc.company = v.company || seed.company || "";
            doc.transaction_date = v.schedule_date || frappe.datetime.now_date();
            doc.schedule_date = v.schedule_date || frappe.datetime.now_date();
            const itemRow = doc.append("items", {});
            itemRow.item_code = v.item_code || seed.item_code || "";
            itemRow.qty = Number(v.qty || seed.qty || 1);
            itemRow.schedule_date = v.schedule_date || frappe.datetime.now_date();
            itemRow.sales_order = v.sales_order || seed.sales_order || "";
            itemRow.production_plan = v.production_plan || seed.production_plan || "";
            itemRow.bom_no = v.bom_no || seed.bom_no || "";
          });
        } else if (actionType === "Create Material Request (Material Transfer)") {
          openDocWithSeed("Material Request", (doc) => {
            doc.material_request_type = "Material Transfer";
            doc.company = v.company || seed.company || "";
            doc.transaction_date = v.schedule_date || frappe.datetime.now_date();
            doc.schedule_date = v.schedule_date || frappe.datetime.now_date();
            doc.set_from_warehouse = v.source_warehouse || "";
            doc.set_warehouse = v.target_warehouse || "";
            const itemRow = doc.append("items", {});
            itemRow.item_code = v.item_code || seed.item_code || "";
            itemRow.qty = Number(v.qty || seed.qty || 1);
            itemRow.schedule_date = v.schedule_date || frappe.datetime.now_date();
            itemRow.from_warehouse = v.source_warehouse || "";
            itemRow.warehouse = v.target_warehouse || "";
            itemRow.sales_order = v.sales_order || seed.sales_order || "";
            itemRow.production_plan = v.production_plan || seed.production_plan || "";
            itemRow.bom_no = v.bom_no || seed.bom_no || "";
          });
        } else if (actionType === "Create Purchase Order") {
          openDocWithSeed("Purchase Order", (doc) => {
            doc.company = v.company || seed.company || "";
            doc.supplier = v.supplier || "";
            doc.schedule_date = v.schedule_date || frappe.datetime.now_date();
            const itemRow = doc.append("items", {});
            itemRow.item_code = v.item_code || seed.item_code || "";
            itemRow.qty = Number(v.qty || seed.qty || 1);
            itemRow.schedule_date = v.schedule_date || frappe.datetime.now_date();
            itemRow.sales_order = v.sales_order || seed.sales_order || "";
          });
        } else if (actionType === "Create Stock Entry") {
          openDocWithSeed("Stock Entry", (doc) => {
            doc.company = v.company || seed.company || "";
            doc.stock_entry_type = "Material Transfer for Manufacture";
            doc.work_order = v.work_order || seed.work_order || "";
            doc.from_warehouse = v.source_warehouse || "";
            doc.to_warehouse = v.target_warehouse || "";
            const itemRow = doc.append("items", {});
            itemRow.item_code = v.item_code || seed.item_code || "";
            itemRow.qty = Number(v.qty || seed.qty || 1);
            itemRow.s_warehouse = v.source_warehouse || "";
            itemRow.t_warehouse = v.target_warehouse || "";
          });
        }
        d.hide();
      }
    });

    const helpByAction = {
      "Create Sales Order": "Create a Sales Order from current context. Customer is required; item and qty can be prefilled.",
      "Create Production Plan": "Create a draft Production Plan with multi-item rows. Best with a submitted Sales Order; each line needs Item, BOM, Qty, UOM, and Planned Start.",
      "Create Work Order": "Create one or more draft Work Orders. Needs Company, Planned Start, Target Warehouse, plus item rows with Item, BOM, and Qty.",
      "Create Material Request (Purchase)": "Raise purchase demand for raw material. Needs Company, Date, Item, Qty; UOM defaults are filled by ERPNext.",
      "Create Material Request (Material Transfer)": "Request material transfer. Needs Company, Date, Item, Qty, and usually Source/Target Warehouse.",
      "Create Purchase Order": "Create procurement order from selected supplier. Needs Supplier, Company, Date, Item, and Qty.",
      "Create Stock Entry": "Create a stock entry draft linked to the selected Work Order. Needs Company, Work Order, Item, Qty, and usually Source/Target Warehouse.",
      "Open Sales Order": "Open an existing Sales Order (use Customer + Sales Order filters).",
      "Open Production Plan": "Open an existing Production Plan.",
      "Open Work Order": "Open an existing Work Order."
    };

    d.fields_dict.action_help.$wrapper.html(
      `<div style="padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#f8fafc;color:#334155;font-size:12px;">
        ${escapeHtml(helpByAction[d.get_value("action_type")] || "")}
      </div>`
    );

    const bindQuery = (fieldname, fn) => {
      if (typeof d.set_query === "function") {
        d.set_query(fieldname, fn);
        return;
      }
      const f = d.fields_dict && d.fields_dict[fieldname];
      if (f) {
        f.get_query = fn;
        if (f.df) f.df.get_query = fn;
      }
    };

    bindQuery("sales_order", () => {
      const filters = {};
      if (d.get_value("customer")) filters.customer = d.get_value("customer");
      if (d.get_value("company")) filters.company = d.get_value("company");
      return { filters };
    });
    bindQuery("work_order", () => {
      const filters = {};
      if (d.get_value("sales_order")) filters.sales_order = d.get_value("sales_order");
      if (d.get_value("item_code")) filters.production_item = d.get_value("item_code");
      if (d.get_value("company")) filters.company = d.get_value("company");
      return { filters };
    });
    bindQuery("production_plan", () => {
      const filters = {};
      if (d.get_value("company")) filters.company = d.get_value("company");
      return { filters };
    });
    bindQuery("bom_no", () => {
      const filters = {};
      if (d.get_value("item_code")) filters.item = d.get_value("item_code");
      filters.is_active = 1;
      return { filters };
    });

    const applyActionMode = () => {
      const mode = d.get_value("action_type") || "";
      d.fields_dict.action_help.$wrapper.html(
        `<div style="padding:10px;border:1px solid #e5e7eb;border-radius:8px;background:#f8fafc;color:#334155;font-size:12px;">
          ${escapeHtml(helpByAction[mode] || "")}
        </div>`
      );
      const isCreateSalesOrder = mode === "Create Sales Order";
      const showWOWh = mode === "Create Work Order";
      setFieldVisibility(d, "source_warehouse", !showWOWh, showWOWh);
      setFieldVisibility(d, "wip_warehouse", !showWOWh, showWOWh);
      setFieldVisibility(d, "target_warehouse", !showWOWh, showWOWh);
      setFieldVisibility(d, "scrap_warehouse", !showWOWh, false);
      const showSupplier = mode === "Create Purchase Order";
      setFieldVisibility(d, "supplier", !showSupplier, showSupplier);
      setFieldVisibility(d, "sales_order", isCreateSalesOrder, false);
      setFieldVisibility(d, "production_plan", isCreateSalesOrder, false);
      setFieldVisibility(d, "work_order", isCreateSalesOrder, false);
      setFieldVisibility(d, "bom_no", isCreateSalesOrder, false);
      const openOnly = (mode || "").startsWith("Open ");
      setFieldVisibility(d, "qty", openOnly, !openOnly);
      setFieldVisibility(d, "schedule_date", openOnly, !openOnly);
    };

    d.fields_dict.action_type.df.onchange = applyActionMode;

    d.fields_dict.item_code.df.onchange = async () => {
      const item = d.get_value("item_code");
      if (!item || d.get_value("bom_no")) return;
      const defaultBom = await getDocValue("Item", item, "default_bom");
      if (defaultBom) d.set_value("bom_no", defaultBom);
    };

    d.fields_dict.bom_no.df.onchange = async () => {
      const bom = d.get_value("bom_no");
      if (!bom || d.get_value("item_code")) return;
      const bomItem = await getDocValue("BOM", bom, "item");
      if (bomItem) d.set_value("item_code", bomItem);
    };

    applyActionMode();
    d.show();
    } catch (e) {
      console.error(e);
      frappe.show_alert({ message: "Failed to open Action Center: " + (e.message || "Unknown error"), indicator: "red" }, 6);
    }
  }

