      sales_order: salesOrderEl?.value || "",
      production_plan: "",
      work_order: workOrderEl?.value || "",
      supplier: "",
      source_warehouse: "",
      wip_warehouse: "",
      target_warehouse: "",
      scrap_warehouse: ""
    };
  }
  window.getDefaultActionSeed = getDefaultActionSeed;
  window.openLegacyActionCenter = openActionCenter;
  window.openActionCenter = openManufacturingControlCenter;
