  window.openProductionPlanCreator = openProductionPlanCreator;
  window.openWorkOrderCreator = openWorkOrderCreator;
  window.openDeliveryNoteCreator = openDeliveryNoteCreator;

  window.openWorkOrderActionCenter = async function(jobCardName) {
    const jc = await getJobCardContext(jobCardName);
    if (!jc) {
      window.openActionCenter(getDefaultActionSeed());
      return;
    }
    window.openActionCenter({
      company: jc.company || companyEl?.value || "",
      item_code: jc.production_item || "",
      bom_no: jc.bom_no || "",
      qty: Math.max(Number(jc.for_quantity || 0) - Number(jc.completed_qty || 0), 1),
      sales_order: jc.sales_order || salesOrderEl?.value || "",
      production_plan: jc.production_plan || "",
      work_order: jc.work_order || workOrderEl?.value || ""
    });
  };

  window.openSalesOrderStatusBoard = function() {
    const d = new frappe.ui.Dialog({
      title: "Sales Order Status Board",
      size: "extra-large",
      fields: [
        { fieldtype: "Section Break" },
        { fieldtype: "Link", fieldname: "company", label: "Company", options: "Company", default: companyEl?.value || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Link", fieldname: "customer", label: "Customer", options: "Customer" },
        { fieldtype: "Column Break" },
        { fieldtype: "Link", fieldname: "sales_order", label: "Sales Order", options: "Sales Order", default: salesOrderEl?.value || "" },
        { fieldtype: "Section Break" },
        { fieldtype: "Date", fieldname: "from_date", label: "From Date", default: ymd(fromDateEl?.value) || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Date", fieldname: "to_date", label: "To Date", default: ymd(toDateEl?.value) || "" },
        { fieldtype: "Column Break" },
        { fieldtype: "Select", fieldname: "so_status", label: "SO Status", options: "\nDraft\nTo Deliver and Bill\nTo Bill\nCompleted\nClosed\nCancelled" },
        { fieldtype: "Section Break" },
        { fieldtype: "Button", fieldname: "load_btn", label: "Load Status Board" },
        { fieldtype: "Section Break" },
        { fieldtype: "HTML", fieldname: "board_html" }
      ]
    });

    const loadBoard = async () => {
      d.fields_dict.board_html.$wrapper.html('<div style="padding:12px;color:#64748b;">Loading...</div>');
      try {
        const v = d.get_values() || {};
        const r = await frappe.call({
          method: "live_production_api",
          args: {
            action: "sales_order_pipeline",
            company: v.company || "",
            customer: v.customer || "",
            sales_order: v.sales_order || "",
            from_date: v.from_date || "",
            to_date: v.to_date || "",
            so_status: v.so_status || ""
          }
        });
        const rawRows = r?.message?.rows || [];

        const badge = (text, bg, color) => `<span style="display:inline-block;padding:3px 8px;border-radius:999px;background:${bg};color:${color};font-weight:700;font-size:11px;">${escapeHtml(text || "-")}</span>`;
        const soBadge = (st) => {
          const s = String(st || "").toLowerCase();
          if (s.includes("completed") || s.includes("closed")) return badge(st, "#dcfce7", "#166534");
          if (s.includes("cancel")) return badge(st, "#fee2e2", "#991b1b");
          if (s.includes("deliver") || s.includes("bill")) return badge(st, "#fef3c7", "#92400e");
          return badge(st || "Draft", "#e0e7ff", "#3730a3");
        };
        const pctBadge = (pct) => {
          const n = Number(pct || 0);
          if (n >= 100) return badge(`${n.toFixed(1)}%`, "#dcfce7", "#166534");
          if (n >= 70) return badge(`${n.toFixed(1)}%`, "#dbeafe", "#1e3a8a");
          if (n >= 30) return badge(`${n.toFixed(1)}%`, "#fef3c7", "#92400e");
          return badge(`${n.toFixed(1)}%`, "#fee2e2", "#991b1b");
        };

        const rowsHtml = rawRows.map((x, i) => {
          const woDone = Number(x.work_order_completed || 0);
          const woTotal = Number(x.work_order_total || 0);
          const woLabel = `${fmt(woDone)}/${fmt(woTotal)}`;
          const woColor = woTotal > 0 && woDone >= woTotal ? "#166534" : "#1d4ed8";
          return `
            <tr>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;"><a href="/app/sales-order/${encodeURIComponent(x.sales_order || "")}" target="_blank" style="color:#1d4ed8;font-weight:700;text-decoration:none;">${escapeHtml(x.sales_order || "")}</a></td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(x.date || "")}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(x.customer || "")}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${soBadge(x.so_status)}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(x.delivery_status || "")}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(x.billing_status || "")}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${escapeHtml(x.production_plans || "")}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">
                <a href="#" data-wo-popup="${i}" style="color:${woColor};font-weight:800;text-decoration:underline;">${woLabel}</a>
              </td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${fmt(x.job_card_completed || 0)}/${fmt(x.job_card_total || 0)}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${fmt(x.stock_entry_count || 0)}</td>
              <td style="padding:8px;border-bottom:1px solid #f1f5f9;">${pctBadge(x.wo_completion_pct || 0)}</td>
            </tr>
          `;
        }).join("");

        const html = `
          <div style="margin:8px 0 10px;color:#475569;font-size:12px;">Rows: ${rawRows.length}</div>
          <div style="overflow:auto;max-height:460px;border:1px solid #e5e7eb;border-radius:10px;">
            <table style="width:100%;border-collapse:collapse;font-size:12px;">
              <thead>
                <tr>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Sales Order</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Date</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Customer</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">SO Status</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Delivery</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Billing</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Production Plan</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Work Orders</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Job Cards</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">Stock Entries</th>
                  <th style="text-align:left;padding:8px;background:#f8fafc;border-bottom:1px solid #e5e7eb;">WO Qty %</th>
                </tr>
              </thead>
              <tbody>${rowsHtml}</tbody>
            </table>
          </div>
        `;
        d.fields_dict.board_html.$wrapper.html(html);

        const openWoJcPopup = (row) => {
          const woRows = (row.wo_details || []).map(w => ({
            "Work Order": w.name || "",
            "Status": w.status || "",
            "Qty": fmt(w.qty || 0),
            "Produced": fmt(w.produced_qty || 0),
            "Completion %": `${Number(w.completion_pct || 0).toFixed(1)}%`
          }));
          const jcRows = (row.jc_details || []).map(j => ({
            "Job Card": j.name || "",
            "Work Order": j.work_order || "",
            "Status": j.status || "",
            "Operation": j.operation || ""
          }));
          const pd = new frappe.ui.Dialog({
            title: `WO/JC List - ${row.sales_order || ""}`,
            size: "large",
            fields: [{ fieldtype: "HTML", fieldname: "body" }]
          });
          pd.fields_dict.body.$wrapper.html(
            `<div style="margin:6px 0 6px;font-weight:800;color:#1e293b;">Work Orders</div>${tableFromRows(woRows, ["Work Order", "Status", "Qty", "Produced", "Completion %"])}
             <div style="margin:12px 0 6px;font-weight:800;color:#1e293b;">Job Cards</div>${tableFromRows(jcRows, ["Job Card", "Work Order", "Status", "Operation"])}`
          );
          pd.show();
        };
        d.fields_dict.board_html.$wrapper.find("[data-wo-popup]").on("click", function(e){
          e.preventDefault();
          const idx = Number(this.getAttribute("data-wo-popup"));
          const row = rawRows[idx];
          if (row) openWoJcPopup(row);
        });
      } catch (e) {
        d.fields_dict.board_html.$wrapper.html(`<div style="padding:12px;color:#b91c1c;">Failed to load: ${escapeHtml(e.message || "Unknown error")}</div>`);
      }
    };

    d.fields_dict.load_btn.$input.css({
      "background": "linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%)",
      "border": "none",
      "color": "#fff",
      "font-weight": "700",
      "border-radius": "8px",
      "padding": "8px 14px"
    });
    d.fields_dict.load_btn.$input.on("click", loadBoard);
    d.show();
    loadBoard();
  };

  window.showSmartSummaryByJobCard = async function(jobCardName) {
    const jc = getJobCardByName(jobCardName);
    if (!jc) {
      frappe.show_alert({ message: "Job Card not found.", indicator: "orange" }, 4);
      return;
    }

    try {
      const r = await frappe.call({
        method: "live_production_api",
        args: {
          action: "smart_summary",
