  function setDefaultDates(){
    const now = new Date();
    // Set to_date to today
    if (toDateEl) toDateEl.value = ymd(now);
    // Set from_date to 10 days back
    const tenDaysAgo = new Date(now);
    tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
    if (fromDateEl) fromDateEl.value = ymd(tenDaysAgo);
  }

  function setDatePreset(preset){
    const now = new Date();
    let from, to;
    switch(preset){
      case "today": from = to = new Date(now); break;
      case "yesterday":
        from = to = new Date(now);
        from.setDate(from.getDate()-1);
        to.setDate(to.getDate()-1);
        break;
      case "this_week":
        from = new Date(now);
        from.setDate(from.getDate() - from.getDay());
        to = new Date(now);
        break;
      case "last_week":
        from = new Date(now);
        from.setDate(from.getDate() - from.getDay() - 7);
        to = new Date(from);
        to.setDate(to.getDate() + 6);
        break;
      case "this_month":
        from = new Date(now.getFullYear(), now.getMonth(), 1);
        to = new Date(now);
        break;
      case "last_month":
        from = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        to = new Date(now.getFullYear(), now.getMonth(), 0);
        break;
      case "this_quarter": {
        const q = Math.floor(now.getMonth() / 3);
        from = new Date(now.getFullYear(), q * 3, 1);
        to = new Date(now);
        break;
      }
      case "last_quarter": {
        const lastQ = Math.floor(now.getMonth() / 3) - 1;
        from = new Date(now.getFullYear(), lastQ * 3, 1);
        to = new Date(now.getFullYear(), (lastQ + 1) * 3, 0);
        break;
      }
      case "this_year":
        from = new Date(now.getFullYear(), 0, 1);
        to = new Date(now);
        break;
      case "last_year":
        from = new Date(now.getFullYear() - 1, 0, 1);
        to = new Date(now.getFullYear() - 1, 11, 31);
        break;
      default:
        return;
    }
    if(fromDateEl) fromDateEl.value = ymd(from);
    if(toDateEl) toDateEl.value = ymd(to);
  }

  function setOptions(selectEl, arr, placeholder){
    if(!selectEl) return;
    const cur = selectEl.value;
    selectEl.innerHTML = `<option value="">${placeholder}</option>`;
    (arr||[]).forEach(v=>{
      const o=document.createElement("option");
      o.value=v; o.textContent=v;
      selectEl.appendChild(o);
    });
    if(cur && (arr||[]).includes(cur)) selectEl.value=cur;
  }

  // ---- Chart.js libs ----
  function ensureChartJSLibs() {
    return new Promise((resolve, reject) => {
      if (window.Chart && window.Chart.registry?.plugins?.get("datalabels")) return resolve();
      const scripts = [
        "https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js",
        "https://cdn.jsdelivr.net/npm/chartjs-plugin-datalabels@2.2.0/dist/chartjs-plugin-datalabels.min.js"
      ];
      let loaded = 0;
      scripts.forEach((src) => {
        const s = document.createElement("script");
        s.src = src;
        s.async = false;
        s.onload = () => {
          if (++loaded === scripts.length) {
            if (window.Chart && window.ChartDataLabels) {
              try { Chart.register(ChartDataLabels); } catch (e) {}
              resolve();
            } else reject("Chart lib failed");
          }
        };
        s.onerror = () => reject("Script load failed: " + src);
        document.head.appendChild(s);
      });
    });
  }

  // Enhanced color palette with gradients
  const enhancedPalette = {
    primary: ["#3b82f6", "#2563eb", "#1d4ed8"],
    success: ["#22c55e", "#16a34a", "#15803d"],
    warning: ["#f59e0b", "#d97706", "#b45309"],
    danger: ["#ef4444", "#dc2626", "#b91c1c"],
    info: ["#0ea5e9", "#0284c7", "#0369a1"],
    purple: ["#a855f7", "#9333ea", "#7e22ce"],
    orange: ["#f97316", "#ea580c", "#c2410c"],
    teal: ["#14b8a6", "#0d9488", "#0f766e"]
  };

  function createGradient(ctx, colorArray, direction = 'vertical') {
    const gradient = direction === 'vertical' 
      ? ctx.createLinearGradient(0, 0, 0, 400)
      : ctx.createLinearGradient(0, 0, 400, 0);
    gradient.addColorStop(0, colorArray[0]);
    gradient.addColorStop(0.5, colorArray[1] || colorArray[0]);
    gradient.addColorStop(1, colorArray[2] || colorArray[1] || colorArray[0]);
    return gradient;
  }

  // Center text plugin (Power BI-style)
  const CenterTextPlugin = {
    id: "centerText",
    afterDraw(chart, args, opts){
      if(!opts || !opts.text) return;
      const {ctx} = chart;
      const meta = chart.getDatasetMeta(0);
      if(!meta || !meta.data || !meta.data[0]) return;
      const x = meta.data[0].x;
      const y = meta.data[0].y;
      ctx.save();
      ctx.textAlign="center";
      ctx.textBaseline="middle";
      const fontSize = opts.fontSize || 24;
      const fontWeight = opts.fontWeight || "900";
      const textColor = opts.color || "#1e293b";
      ctx.fillStyle = textColor;
      ctx.font = `${fontWeight} ${fontSize}px ui-sans-serif, system-ui`;
      // Add text shadow for better visibility on white background
      ctx.shadowColor = "rgba(255, 255, 255, 0.8)";
      ctx.shadowBlur = 2;
      ctx.shadowOffsetX = 0;
      ctx.shadowOffsetY = 0;
      ctx.fillText(opts.text, x, y);
      ctx.restore();
    }
  };

  function buildArgs(){
    return {
      from_date: (fromDateEl?.value||"").trim(),
      to_date: (toDateEl?.value||"").trim(),
      company: companyEl?.value || "",
      group: groupEl?.value || "",
      party: partyEl?.value || "",
      extra: extraEl?.value || "",
      work_order: workOrderFilterEl?.value || "",
      sales_order: salesOrderFilterEl?.value || "",
    };
  }

  // Map UI args to API args expected by server script (keeps your existing mapping behavior)
  document.DASH_BUILD_ARGS_OVERRIDE = function(args){
    args.status = args.group || "";
    args.production_item = args.party || "";
    args.workstation = args.extra || "";
    delete args.group; delete args.party; delete args.extra;
    return args;
  };

  async function callAPI(methodName, args){
    if(typeof frappe === "undefined" || !frappe.call){
      throw new Error("Frappe framework not loaded. Please run this inside ERPNext / Frappe desk.");
    }
    return new Promise((resolve,reject)=>{
      frappe.call({
        method: methodName,
        args,
        callback: (r)=> r?.message ? resolve(r.message) : reject(new Error("Empty response")),
        error: (err)=>reject(err)
      });
    });
  }

  // ---- Data grouping for charts ----
  const palette = {
    primary: "#2563eb",
    success: "#16a34a",
    warning: "#f59e0b",
    danger: "#dc2626",
    slate: "#64748b",
    gray: "#94a3b8"
  };

  function groupForDonut(rows){
    const map = {};
    (rows||[]).forEach(r=>{
      const g = r.group || "(Blank)";
      map[g] = (map[g]||0) + Number(r.amount||0);
    });
    const labels = Object.keys(map);
    const colorSets = [
      enhancedPalette.primary,
      enhancedPalette.success,
      enhancedPalette.warning,
      enhancedPalette.danger,
      enhancedPalette.info,
      enhancedPalette.purple,
      enhancedPalette.orange,
      enhancedPalette.teal
    ];
    const colors = labels.map((_,i)=>{
      return colorSets[i % colorSets.length][0];
    });
    const gradients = labels.map((_,i)=>{
      return colorSets[i % colorSets.length];
    });
    const total = labels.reduce((s,k)=>s+map[k],0);
    return {labels, data: labels.map(l=>map[l]), colors, gradients, total};
  }

  function monthKey(dateStr){
    const d = new Date(dateStr);
    if(isNaN(d)) return null;
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;
  }
  function monthLabel(key){
    const [y,m]=key.split("-");
    return new Date(Number(y),Number(m)-1,1).toLocaleString(undefined,{month:"short", year:"numeric"});
  }
  function dayKey(dateStr){
    const d = new Date(dateStr);
    if(isNaN(d)) return null;
    return String(dateStr).slice(0,10);
  }
  function dayLabel(key){
    const d = new Date(key);
    return d.toLocaleDateString(undefined,{month:"short", day:"numeric"});
  }
  function weekKey(dateStr){
    const d = new Date(dateStr);
    if(isNaN(d)) return null;
    const year = d.getFullYear();
    const startOfYear = new Date(year, 0, 1);
    const days = Math.floor((d - startOfYear) / (24 * 60 * 60 * 1000));
    const week = Math.floor(days / 7) + 1;
    return `${year}-W${String(week).padStart(2,"0")}`;
  }
  function weekLabel(key){
    const [y,w]=key.split("-W");
    return `W${w} ${y}`;
  }
  function quarterKey(dateStr){
    const d = new Date(dateStr);
    if(isNaN(d)) return null;
    const quarter = Math.floor(d.getMonth() / 3) + 1;
    return `${d.getFullYear()}-Q${quarter}`;
  }
  function quarterLabel(key){
    const [y,q]=key.split("-Q");
    return `Q${q} ${y}`;
  }
  function yearKey(dateStr){
    const d = new Date(dateStr);
    if(isNaN(d)) return null;
    return String(d.getFullYear());
  }
  function yearLabel(key){ return key; }

  function groupForPeriodStack(rows, period){
    // rows: [{date, planned, produced}]
    const map = {};
    let keyFunc, labelFunc;
    switch(period){
      case "daily": keyFunc = dayKey; labelFunc = dayLabel; break;
      case "weekly": keyFunc = weekKey; labelFunc = weekLabel; break;
      case "quarterly": keyFunc = quarterKey; labelFunc = quarterLabel; break;
      case "yearly": keyFunc = yearKey; labelFunc = yearLabel; break;
      default: keyFunc = monthKey; labelFunc = monthLabel;
    }

    (rows||[]).forEach(r=>{
      const k = keyFunc(r.date);
      if(!k) return;
      map[k] = map[k] || {planned:0, produced:0};
      map[k].planned += Number(r.planned||0);
      map[k].produced += Number(r.produced||0);
    });

    const keys = Object.keys(map).sort();
    const labels = keys.map(labelFunc);

    const planned = keys.map(k=>map[k].planned);
    const produced = keys.map(k=>map[k].produced);
    const completionPct = keys.map((k,i)=>{
      const p = planned[i] || 0;
      const pr = produced[i] || 0;
      return p ? (pr/p)*100 : 0;
    });

    return {labels, planned, produced, completionPct};
  }

  function computeWorkstationBottlenecks(filteredData){
    const opsByWo = filteredData?.operations_by_wo || {};
    const map = {}; // ws -> {time, qty, ops}
    Object.keys(opsByWo).forEach(wo=>{
      (opsByWo[wo]||[]).forEach(op=>{
        const ws = op.workstation || "(No Workstation)";
        map[ws] = map[ws] || {time:0, qty:0, ops:0};
        map[ws].time += Number(op.time_in_mins||0);
        map[ws].qty  += Number(op.completed_qty||0);
        map[ws].ops  += 1;
      });
    });
    const rows = Object.keys(map).map(ws=>({
      workstation: ws,
      time_mins: map[ws].time,
      completed_qty: map[ws].qty,
      time_per_qty: map[ws].qty ? (map[ws].time / map[ws].qty) : null,
      operations: map[ws].ops
    })).sort((a,b)=> (b.time_mins||0)-(a.time_mins||0));
    const top = rows.slice(0, 10);
    return {
      rows,
      labels: top.map(r=>r.workstation),
      data: top.map(r=>Math.round(r.time_mins||0)),
    };
  }

  function computeEmployeeProductivity(filteredData){
    const logs = filteredData?.employee_time_logs || [];
    const map = {}; // emp -> {time, qty}
    logs.forEach(l=>{
      const emp = l.employee || "(No Employee)";
      map[emp] = map[emp] || {time:0, qty:0};
      map[emp].time += Number(l.time_in_mins||0);
      map[emp].qty  += Number(l.completed_qty||0);
    });
    const rows = Object.keys(map).map(emp=>{
      const time = map[emp].time;
      const qty = map[emp].qty;
      const hours = time/60;
      return {
        employee: emp,
        time_mins: time,
        completed_qty: qty,
        qty_per_hour: hours>0 ? (qty/hours) : null,
        time_per_unit: qty>0 ? (time/qty) : null
      };
    }).filter(r=> (r.time_mins||0) > 0).sort((a,b)=> (b.qty_per_hour||0)-(a.qty_per_hour||0));
    const top = rows.slice(0, 10);
    return {
      rows,
      labels: top.map(r=>r.employee),
      data: top.map(r=>Number((r.qty_per_hour||0).toFixed(2)))
    };
  }

  function computeOEEProxy(filteredData){
    // Proxy-only: based on fields we have (no downtime/ideal cycle time/reject segregation).
    const wos = filteredData?.work_orders || [];
    const jobCards = filteredData?.job_cards || [];
    const planned = wos.reduce((s,r)=> s + Number(r.qty||0), 0);
    const produced = wos.reduce((s,r)=> s + Number(r.produced_qty||0), 0);
    const performance = planned ? (produced/planned) : null; // proxy
    const jcCompleted = jobCards.reduce((s,r)=> s + Number(r.total_completed_qty||0), 0);
    const jcLoss = jobCards.reduce((s,r)=> s + Number(r.process_loss_qty||0), 0);
    const quality = jcCompleted ? ((Math.max(jcCompleted - jcLoss, 0))/jcCompleted) : null; // proxy
    const availability = null; // needs downtime/shift time
    const oee = (availability!==null && performance!==null && quality!==null) ? (availability*performance*quality) : null;
    return {availability, performance, quality, oee};
  }

  // ---- KPI rendering (Sales BI-style with colored left borders) ----
  function kpiCard(label, value, dotClass, metaLeft, metaRight, icon = ""){
    // Production color scheme (blue/teal/orange instead of purple)
    const colorMap = {
      'primary': { gradient: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)', bg: 'rgba(59, 130, 246, 0.1)' },
      'success': { gradient: 'linear-gradient(135deg, #22c55e 0%, #16a34a 100%)', bg: 'rgba(34, 197, 94, 0.1)' },
      'warning': { gradient: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)', bg: 'rgba(245, 158, 11, 0.1)' },
      'danger': { gradient: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)', bg: 'rgba(239, 68, 68, 0.1)' },
      'slate': { gradient: 'linear-gradient(135deg, #0ea5e9 0%, #0284c7 100%)', bg: 'rgba(14, 165, 233, 0.1)' }
    };
    const colors = colorMap[dotClass] || colorMap['primary'];

    const meta = (metaLeft || metaRight) ? `<div style="margin-top:8px;font-size:11px;color:#64748b;font-weight:600;">${metaLeft || ''}${metaRight ? (metaLeft ? ' • ' : '') + metaRight : ''}</div>` : '';

    return `
