  };

  function renderKPIs(rawData, filteredWorkOrders){
    if(!kpiRowEl) return;
    const wos = filteredWorkOrders || [];
    const jobCards = rawData?.job_cards || [];
    const empLogs = rawData?.employee_time_logs || [];
    const opsByWo = rawData?.operations_by_wo || {};

    const woPlanned = wos.reduce((s,r)=> s + (Number(r.qty)||0), 0);
    const woProduced = wos.reduce((s,r)=> s + (Number(r.produced_qty)||0), 0);
    const woRemaining = Math.max(woPlanned - woProduced, 0);
    const woRate = woPlanned ? (woProduced/woPlanned)*100 : 0;

    const woOpen = wos.filter(w=>String(w.status||"").toLowerCase().includes("not") || String(w.status||"").toLowerCase().includes("open")).length;
    const woCompleted = wos.filter(w=>String(w.status||"").toLowerCase().includes("complete")).length;

    const jcCount = jobCards.length;
    const jcCompleted = jobCards.reduce((s,r)=> s + (Number(r.total_completed_qty)||0), 0);
    const jcLoss = jobCards.reduce((s,r)=> s + (Number(r.process_loss_qty)||0), 0);
    const jcTime = jobCards.reduce((s,r)=> s + (Number(r.total_time_in_mins)||0), 0);

    const uniqEmp = new Set(empLogs.map(r=>r.employee).filter(Boolean)).size;
    const empTime = empLogs.reduce((s,r)=> s + (Number(r.time_in_mins)||0), 0);
    const empCompleted = empLogs.reduce((s,r)=> s + (Number(r.completed_qty)||0), 0);

    let opCount = 0, opTime = 0;
    Object.keys(opsByWo||{}).forEach(wo=>{
      (opsByWo[wo]||[]).forEach(op=>{
        opCount += 1;
        opTime += Number(op.time_in_mins||0);
      });
    });


    const prod = computeEmployeeProductivity(rawData || {});
    const qtyPerHour = (empTime>0) ? (empCompleted / (empTime/60)) : 0;
    const timePerUnit = (empCompleted>0) ? (empTime / empCompleted) : 0;

    const oee = computeOEEProxy(rawData || {});
    const perfPct = oee.performance!==null ? (oee.performance*100) : null;
    const qualPct = oee.quality!==null ? (oee.quality*100) : null;

    const jcCompletedCount = jobCards.filter(jc => String(jc.status || "").trim().toLowerCase() === "completed").length;
    const jcPendingCount = jobCards.length - jcCompletedCount;

    kpiRowEl.innerHTML = `
      ${kpiCard("WO Total Qty", fmt(woPlanned), "primary", "Work Orders: " + fmt(wos.length), "", kpiIcons["WO Total Qty"])}
      ${kpiCard("WO Completed Qty", fmt(woProduced), "success", "From produced qty", "", kpiIcons["WO Completed Qty"])}
      ${kpiCard("WO Pending Qty", fmt(woRemaining), "warning", "Total - Completed", "", kpiIcons["WO Pending Qty"])}
      ${kpiCard("JC Total", fmt(jcCount), "primary", "All filtered job cards", "", kpiIcons["JC Total"])}
      ${kpiCard("JC Pending", fmt(jcPendingCount), "warning", "Status != Completed", "", kpiIcons["JC Pending"])}
      ${kpiCard("JC Completed", fmt(jcCompletedCount), "success", "Status = Completed", "", kpiIcons["JC Completed"])}
      ${kpiCard("Planned Qty", fmt(woPlanned), "primary", "Work Orders: " + fmt(wos.length), "", kpiIcons["Planned Qty"])}
      ${kpiCard("Produced Qty", fmt(woProduced), "success", "Completion: " + fmt1(woRate) + "%", "", kpiIcons["Produced Qty"])}
      ${kpiCard("Remaining Qty", fmt(woRemaining), "warning", "Completed WOs: " + fmt(woCompleted), "", kpiIcons["Remaining Qty"])}
      ${kpiCard("Job Cards", fmt(jcCount), "primary", "JC Completed: " + fmt(jcCompleted), "", kpiIcons["Job Cards"])}

      ${kpiCard("Process Loss", fmt(jcLoss), "danger", "JC Time (mins): " + fmt(jcTime), "", kpiIcons["Process Loss"])}
      ${kpiCard("Employees", fmt(uniqEmp), "primary", "Employee time (mins): " + fmt(empTime), "", kpiIcons["Employees"])}
      ${kpiCard("Qty / Hour", fmt1(qtyPerHour), "success", "Time / Unit (mins): " + fmt1(timePerUnit), "", kpiIcons["Qty / Hour"])}
      ${kpiCard("OEE (Proxy)", (perfPct!==null && qualPct!==null) ? fmt1((perfPct/100)*(qualPct/100)*100) + "%" : "—", "slate", "Performance: " + (perfPct!==null? fmt1(perfPct)+'%':'—') + " • Quality: " + (qualPct!==null? fmt1(qualPct)+'%':'—'), "", kpiIcons["OEE (Proxy)"])}
    `;

  }

  // ---- Rendering tables with deep links + row limiting ----
  function escapeHtml(s){
    return String(s ?? "")
      .replace(/&/g,"&amp;")
      .replace(/</g,"&lt;")
      .replace(/>/g,"&gt;")
      .replace(/"/g,"&quot;")
      .replace(/'/g,"&#039;");
  }

  function erpLink(doctype, name){
    if(!name) return "";
    // desk route
    const route = `/app/${doctype}/${encodeURIComponent(name)}`;
    return route;
  }

  function applySearch(rows, cols, query){
    const q = (query||"").trim().toLowerCase();
    if(!q) return rows;
    // Fast filter: only check first N cols if too many
    const useCols = (cols||[]).slice(0, 12);
    return rows.filter(r=>{
      for(const c of useCols){
        const v = r[c];
        if(v === null || v === undefined) continue;
        if(String(v).toLowerCase().includes(q)) return true;
      }
      return false;
    });
  }

  function renderTable(containerEl, rows, columns, title, opts){
    if(!containerEl) return;
    const options = opts || {};
    let cols = Array.isArray(columns) && columns.length ? columns : (rows?.[0] ? Object.keys(rows[0]) : []);
    if(!cols.length){
      containerEl.innerHTML = `<div class="hint">No columns available.</div>`;
      return;
    }

    const q = (lastSearch||"").trim();
    const filteredRows = applySearch(rows||[], cols, q);

    // Keep original order when requested (used by grouped Employee rows).
    const sortedRows = options.preserveOrder ? [...filteredRows] : [...filteredRows].sort((a, b) => {
      const statusA = String(a.status || a.Status || '').toLowerCase();
      const statusB = String(b.status || b.Status || '').toLowerCase();

      // Priority: In Process/Started > Not Started > Completed > Others
      const getPriority = (status) => {
        if(status.includes('in process') || status.includes('started') || status.includes('in progress')) return 1;
        if(status.includes('not start')) return 2;
        if(status.includes('complete')) return 3;
        return 4;
      };

      const priorityA = getPriority(statusA);
      const priorityB = getPriority(statusB);

      if(priorityA !== priorityB) return priorityA - priorityB;

      // If same priority, sort by name/ID (current entry)
      const nameA = a.name || a["Work Order"] || a["Job Card"] || '';
      const nameB = b.name || b["Work Order"] || b["Job Card"] || '';
      return nameA.localeCompare(nameB);
    });

    const limit = options.rowLimit || 1200; // performance cap
    const limited = sortedRows.slice(0, limit);
    const truncated = sortedRows.length > limit;

    const thead = cols.map(c=>`<th>${escapeHtml(c)}</th>`).join("");

    // Status color mapping - includes all Job Card and Work Order statuses
    function getStatusColor(status){
      if(!status) return '';
      const s = String(status).toLowerCase();

      // Completed/Complete - Green
      if(s.includes('complete') || s.includes('completed')) return 'background:#22c55e;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Work In Progress/In Process/Started - Blue
      if(s.includes('work in progress') || s.includes('in progress') || s.includes('in process') || s.includes('started') || s.includes('start')) return 'background:#3b82f6;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Material Transferred - Teal
      if(s.includes('material transferred')) return 'background:#14b8a6;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // On Hold/Pause - Orange
      if(s.includes('on hold') || s.includes('pause') || s.includes('hold')) return 'background:#f59e0b;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Submitted - Purple
      if(s.includes('submitted')) return 'background:#a855f7;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Cancelled/Cancel - Red
      if(s.includes('cancel') || s.includes('cancelled')) return 'background:#ef4444;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Pending/Not Started/Open - Gray
      if(s.includes('pending') || s.includes('not start') || s.includes('not started') || s.includes('open')) return 'background:#94a3b8;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      // Stopped - Orange
      if(s.includes('stop') || s.includes('stopped')) return 'background:#f59e0b;color:#ffffff;padding:4px 8px;border-radius:4px;font-weight:700;';

      return '';
    }

    function cellHtml(c, row){
      const v = row[c];
      const s = (typeof v === "number") ? fmt(v) : (v ?? "");
      const raw = escapeHtml(s);

      // Status column with color background
      if(c === "status" || c === "Status"){
        const statusStyle = getStatusColor(v);
        if(statusStyle){
          return `<span style="${statusStyle}">${raw}</span>`;
        }
      }

      // Deep links
      if(options.linkColumns && options.linkColumns[c]){
        const href = options.linkColumns[c](v, row);
        if(href) return `<a class="link" href="${href}">${raw}</a>`;
      }
      return raw;
    }

    const tbody = limited.map(r=>{
      const tds = cols.map(c=>`<td>${cellHtml(c, r)}</td>`).join("");
      return `<tr>${tds}</tr>`;
    }).join("");

    const hint = truncated
      ? `<div class="hint">Showing first ${fmt(limit)} of ${fmt(sortedRows.length)} rows (for performance). Narrow filters or search to see specific records.</div>`
      : `<div class="hint">Rows: ${fmt(sortedRows.length)}${q ? ` (filtered by “${escapeHtml(q)}”)` : ""}</div>`;

    containerEl.innerHTML = `
      ${hint ? `<div style="margin-bottom:12px;font-size:12px;color:#64748b;font-weight:600;">${hint}</div>` : ''}
      <div style="overflow-x:auto;max-height:600px;border:1px solid #e5e7eb;border-radius:8px;">
        <table style="width:100%;border-collapse:collapse;font-size:13px;">
          <thead>
            <tr style="background:linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #0ea5e9 100%);color:#fff;">
              ${thead}
            </tr>
          </thead>
          <tbody>${tbody}</tbody>
        </table>
      </div>
    `;

    // Apply Sales BI table header styling
    const ths = containerEl.querySelectorAll('th');
    ths.forEach(th => {
      th.style.padding = '12px';
      th.style.textAlign = 'left';
      th.style.fontWeight = '700';
      th.style.position = 'sticky';
      th.style.top = '0';
      th.style.zIndex = '10';
      th.style.background = 'linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #0ea5e9 100%)';
    });

    // Apply Sales BI table row styling
    const trs = containerEl.querySelectorAll('tbody tr');
    trs.forEach((tr, i) => {
      const rowData = limited[i] || {};
      const firstCol = cols?.[0];
      const isGroupHeaderRow = !!(
        options.groupHeaderRows &&
        firstCol &&
        rowData[firstCol] &&
        cols.slice(1).every(c => !rowData[c])
      );

      tr.style.borderBottom = '1px solid #e5e7eb';
      tr.style.transition = 'background 0.2s';
      if (isGroupHeaderRow) {
        tr.style.background = '#e7f0ff';
        tr.setAttribute('onmouseover', "this.style.background='#dbe8ff'");
        tr.setAttribute('onmouseout', "this.style.background='#e7f0ff'");
      } else {
        tr.setAttribute('onmouseover', "this.style.background='#f8fafc'");
        tr.setAttribute('onmouseout', "this.style.background=''");
      }

      const tds = tr.querySelectorAll('td');
      tds.forEach(td => {
        td.style.padding = '12px';
        td.style.color = '#334155';
        if (td.textContent.trim() && !isNaN(parseFloat(td.textContent.replace(/,/g, '')))) {
          td.style.textAlign = 'right';
          td.style.fontWeight = '700';
          td.style.fontFamily = 'monospace';
          td.style.color = '#1e293b';
        } else {
          td.style.fontWeight = '600';
        }
        if (isGroupHeaderRow) {
          td.style.fontWeight = td.cellIndex === 0 ? '800' : '600';
          td.style.color = td.cellIndex === 0 ? '#1e3a8a' : '#334155';
        }
      });
    });

    // Row click drill-down / interactions
    if(typeof options.onRowClick === "function"){
      trs.forEach((tr, i)=>{
        tr.style.cursor = "pointer";
        tr.addEventListener("click", (ev)=>{
          // Avoid hijacking link clicks
          if(ev.target && (ev.target.tagName === "A")) return;
          const row = limited[i];
          if(row) options.onRowClick(row, i);
        });
      });
    }
  }

  // ---- Chart rendering ----
  async function renderDonutOn(canvasEl, payload, title){
    if(!canvasEl) return;
    await ensureChartJSLibs();
    try{ Chart.register(CenterTextPlugin); } catch(e){}
    if(canvasEl._chart){ canvasEl._chart.destroy(); canvasEl._chart=null; }

    if(!payload.labels.length){
      const ctx = canvasEl.getContext("2d");
      if(ctx) ctx.clearRect(0,0,canvasEl.width || 400,canvasEl.height || 400);
      return;
    }

    const ctx = canvasEl.getContext("2d");
    // Get container dimensions for responsive sizing
    const container = canvasEl.parentElement;
    const containerWidth = container ? Math.max(container.clientWidth, 300) : 400;
    const containerHeight = container ? Math.max(container.clientHeight, 150) : 200;

    // Set canvas size based on container (but don't set width/height attributes - let Chart.js handle it)
    // canvasEl.width = containerWidth;
    // canvasEl.height = containerHeight;

    const gradients = payload.gradients || payload.colors.map(c => [c, c, c]);
    const backgroundColor = payload.labels.map((_, i) => {
      const grad = ctx.createLinearGradient(0, 0, 0, containerHeight);
      const colors = gradients[i] || [payload.colors[i], payload.colors[i], payload.colors[i]];
      grad.addColorStop(0, colors[0] + "FF");
      grad.addColorStop(0.5, (colors[1] || colors[0]) + "E6");
      grad.addColorStop(1, (colors[2] || colors[1] || colors[0]) + "CC");
      return grad;
    });

    canvasEl._chart = new Chart(ctx, {
      type:"doughnut",
      data:{
        labels: payload.labels,
        datasets:[{
          label:title||"Total",
          data: payload.data,
          backgroundColor: backgroundColor,
          borderWidth: 3,
          borderColor: 'rgba(15, 23, 42, 0.8)',
          hoverBorderWidth: 4,
          hoverBorderColor: 'rgba(255, 255, 255, 0.3)'
        }]
      },
      options:{
        responsive:true,
        maintainAspectRatio: false,
        aspectRatio: 1.2,
        cutout: "70%",
        animation: {
          animateRotate: true,
          animateScale: true,
          duration: 1200,
          easing: 'easeOutQuart'
        },
        plugins:{
          legend:{
            display:true, 
            position:"bottom",
            labels: {
              padding: 6,
              usePointStyle: true,
              pointStyle: 'circle',
              font: { size: 9, weight: '600' },
              color: '#334155'
            }
          },
          title:{
            display:false
          },
          centerText: { 
            text: fmt(payload.total || 0),
            fontSize: 18,
            fontWeight: '900',
            color: '#1e293b'
          },
          datalabels: {
            display: true,
            color: '#1e293b',
            font: { weight: 'bold', size: 9 },
            textStrokeColor: 'rgba(255,255,255,0.8)',
            textStrokeWidth: 1.5,
            formatter: (value, ctx) => {
              const total = ctx.dataset.data.reduce((a, b) => a + b, 0);
              const pct = total > 0 ? ((value / total) * 100).toFixed(1) : 0;
              return pct >= 5 ? (pct + "%") : "";
            }
          },
          tooltip: {
            backgroundColor: 'rgba(15, 23, 42, 0.95)',
            titleColor: '#f8fafc',
            bodyColor: '#e5e7eb',
            borderColor: 'rgba(148, 163, 184, 0.3)',
            borderWidth: 1,
            padding: 12,
            cornerRadius: 8,
            displayColors: true,
            callbacks: {
              label: function(context) {
                const total = context.dataset.data.reduce((a, b) => a + b, 0);
                const pct = total > 0 ? ((context.parsed / total) * 100).toFixed(1) : 0;
                return `${context.label}: ${fmt(context.parsed)} (${pct}%)`;
              }
            }
          }
        }
      }
    });
  }

