  async function renderSimpleBar(canvasEl, labels, data, title){
    if(!canvasEl) return;
    await ensureChartJSLibs();
    if(canvasEl._chart){ canvasEl._chart.destroy(); canvasEl._chart=null; }
    if(!labels || !labels.length){
      const ctx = canvasEl.getContext("2d");
      if(ctx) ctx.clearRect(0,0,canvasEl.width || 800,canvasEl.height || 400);
      return;
    }

    // Get container dimensions for responsive sizing
    const container = canvasEl.parentElement;
    const containerWidth = container ? Math.max(container.clientWidth, 600) : 800;
    const containerHeight = container ? Math.max(container.clientHeight, 250) : 400;

    // Don't set canvas width/height attributes - let Chart.js handle responsive sizing
    // canvasEl.width = containerWidth;
    // canvasEl.height = containerHeight;

    const ctx = canvasEl.getContext("2d");
    const isProductivity = title.toLowerCase().includes('productivity') || title.toLowerCase().includes('qty/hour');
    const colorSet = isProductivity ? enhancedPalette.success : enhancedPalette.info;
    const gradient = createGradient(ctx, colorSet, 'vertical');

    canvasEl._chart = new Chart(ctx, {
      type:"bar",
      data:{ 
        labels, 
        datasets:[{ 
          label: title||"", 
          data,
          backgroundColor: gradient,
          borderColor: colorSet[1],
          borderWidth: 2,
          borderRadius: 8,
          borderSkipped: false
        }]
      },
      options:{
        responsive:true,
        maintainAspectRatio: false,
        aspectRatio: 2.5,
        animation: {
          duration: 1500,
          easing: 'easeOutQuart'
        },
        layout: {
          padding: {
            top: 10,
            right: 20,
            bottom: 10,
            left: 10
          }
        },
        plugins:{
          legend:{display:false},
          title:{display:false},
          datalabels:{ 
            display: true,
            anchor: 'end',
            align: 'top',
            color: '#ffffff',
            font: { weight: 'bold', size: 10 },
            textStrokeColor: 'rgba(0,0,0,0.5)',
            textStrokeWidth: 2,
            formatter: (value) => {
              if (isProductivity) return value.toFixed(1);
              return fmt(value);
            }
          },
          tooltip: {
            backgroundColor: 'rgba(15, 23, 42, 0.95)',
            titleColor: '#f8fafc',
            bodyColor: '#e5e7eb',
            borderColor: 'rgba(148, 163, 184, 0.3)',
            borderWidth: 1,
            padding: 12,
            cornerRadius: 8,
            displayColors: true,
            callbacks: {
              label: function(context) {
                if (!context || !context.parsed || context.parsed.y === null || context.parsed.y === undefined) return '';
                if (isProductivity) {
                  return `${context.parsed.y.toFixed(2)} units/hour`;
                }
                return `${fmt(context.parsed.y)} minutes`;
              }
            }
          }
        },
        scales:{ 
          x: {
            grid: {
              color: 'rgba(148, 163, 184, 0.1)',
              drawBorder: false
            },
            ticks: {
              color: '#334155',
              font: { size: 10, weight: '600' },
              maxRotation: 45,
              minRotation: 45,
              autoSkip: true,
              maxTicksLimit: 15
            }
          },
          y:{ 
            beginAtZero:true,
            grid: {
              color: 'rgba(148, 163, 184, 0.1)',
              drawBorder: false
            },
            ticks: {
              color: '#334155',
              font: { size: 10, weight: '600' },
              callback: function(value) {
                if (isProductivity) return value.toFixed(1);
                return fmt(value);
              }
            },
            title: {
              display: true,
              text: isProductivity ? 'Units/Hour' : 'Time (Minutes)',
              color: '#334155',
              font: { size: 11, weight: '700' }
            }
          }
        }
      }
    });
  }

  // ---- filtering & transform ----
  function refreshDistinct(distinct){
    if(!distinct) return;
    cachedDistinct = distinct;
    setOptions(companyEl, distinct.companies || [], "All Companies");
    setOptions(groupEl, distinct.groups || [], "All Status");
    setOptions(partyEl, distinct.parties || [], "All Production Items");
    setOptions(extraEl, distinct.extras || [], "All Workstations");
    setOptions(workOrderFilterEl, distinct.work_orders || [], "All Work Orders");
    setOptions(salesOrderFilterEl, distinct.sales_orders || [], "All Sales Orders");
  }

  function filterCachedWorkOrders(){
    if(!cachedAllWorkOrders?.length) return [];
    const allJobCards = cachedRawData?.job_cards || [];
    const opsByWo = cachedRawData?.operations_by_wo || {};
    const jcByWo = {};
    allJobCards.forEach(jc => {
      const wo = jc?.work_order;
      if (!wo) return;
      if (!jcByWo[wo]) jcByWo[wo] = [];
      jcByWo[wo].push(jc);
    });

    let filtered = [...cachedAllWorkOrders];
    if(companyEl?.value) filtered = filtered.filter(r => r.company === companyEl.value);
    if(partyEl?.value) filtered = filtered.filter(r => r.production_item === partyEl.value);
    if(workOrderFilterEl?.value) filtered = filtered.filter(r => r.name === workOrderFilterEl.value);
    if(salesOrderFilterEl?.value) filtered = filtered.filter(r => (r.sales_order || "") === salesOrderFilterEl.value);
    if(extraEl?.value){
      const ws = extraEl.value;
      filtered = filtered.filter(wo => {
        const woName = wo?.name;
        const hasOp = (opsByWo[woName] || []).some(op => (op?.workstation || "") === ws);
        const hasJc = (jcByWo[woName] || []).some(jc => (jc?.workstation || "") === ws);
        return hasOp || hasJc;
      });
    }
    if(groupEl?.value){
      const st = groupEl.value;
      filtered = filtered.filter(wo => {
        const woMatch = (wo?.status || "") === st;
        const jcMatch = (jcByWo[wo?.name] || []).some(jc => (jc?.status || "") === st);
        return woMatch || jcMatch;
      });
    }
    return filtered;
  }

  function buildFilteredData(){
    const selectedStatus = groupEl?.value || "";
    const selectedWorkstation = extraEl?.value || "";
    const selectedProductionItem = partyEl?.value || "";
    const filteredWorkOrders = filterCachedWorkOrders();
    const filteredWoNames = new Set(filteredWorkOrders.map(wo => wo.name));
    const woStatusByName = {};
    filteredWorkOrders.forEach(wo => {
      if (wo?.name) woStatusByName[wo.name] = wo.status || "";
    });

    let jobCards = (cachedRawData.job_cards || []).filter(jc => filteredWoNames.has(jc.work_order));
    if (selectedStatus) {
      const st = selectedStatus;
      jobCards = jobCards.filter(jc => (jc.status || "") === st || (woStatusByName[jc.work_order] || "") === st);
    }
    if (selectedWorkstation) {
      jobCards = jobCards.filter(jc => (jc.workstation || "") === selectedWorkstation);
    }
    if (selectedProductionItem) {
      jobCards = jobCards.filter(jc => (jc.production_item || "") === selectedProductionItem);
    }
    const filteredJobCardNames = new Set(jobCards.map(jc => jc.name));

    const employeeLogs = (cachedRawData.employee_time_logs || []).filter(l => {
      if (!filteredWoNames.has(l.work_order)) return false;
      if (!selectedStatus) return true;
      const jc = l.job_card || "";
      return filteredJobCardNames.has(jc) || (woStatusByName[l.work_order] || "") === selectedStatus;
    });

    const opsByWo = cachedRawData.operations_by_wo || {};
    const filteredOpsByWo = {};
    filteredWoNames.forEach(wo=>{
      const list = opsByWo[wo] || [];
      filteredOpsByWo[wo] = selectedWorkstation
        ? list.filter(op => (op.workstation || "") === selectedWorkstation)
        : list;
    });

    return {
      work_orders: filteredWorkOrders,
      job_cards: jobCards,
      employee_time_logs: employeeLogs,
      operations_by_wo: filteredOpsByWo,
      sales_orders: (cachedRawData.sales_orders || []),
      production_plans: (cachedRawData.production_plans || []),
      distinct_values: cachedDistinct
    };
  }

  // ---- transform config (kept compatible with v2 but upgraded) ----
  window.DASH_CFG = {
    apiMethod: "work_order_dashboard_api",
    exportName: "production_dashboard_export.csv",
    exportEmployeeName: "employee_production_export.csv",
    exportJobCardName: "job_card_export.csv",

    columnsWO: [
      "planned_start_date","planned_end_date","name","item_name",
      "qty","produced_qty","remaining_qty","completion_%","status"
    ],
    columnsOPS: ["Work Order","Operation","Workstation","Status","Time (Mins)","Completed Qty"],
    columnsJC: [
      "Job Card","Work Order","Production Item","Operation",
      "Posting Date","Status","For Qty","Completed Qty","Process Loss Qty",
      "Expected Start","Expected End","Actual Start","Actual End",
      "Time Required (Mins)","Total Time (Mins)"
    ],
    columnsJCStatus: ["Job Card Number","Date","Work Order","Item Name","Status"],
    columnsSO: ["Sales Order","Date","Customer","Status","Delivery Status","Work Order No","Production Plan No"],
    columnsPP: ["Production Plan","Date","Status","Work Order No","Sales Order No"],
    columnsEMPByEmployee: ["Employee","Work Order","Job Card","Operation","From Time","To Time","Time (Mins)","Completed Qty","Item Name"],
    columnsEMP: [
      "Work Order","Job Card","Employee","Operation","From Time","To Time","Time (Mins)","Completed Qty","Item Name"
    ],
    // Transform -> produce all table rows + chart rows
    transform: function (m) {
      const wos = m.work_orders || [];
      const jobCards = m.job_cards || [];
      const employeeLogs = m.employee_time_logs || [];
      const opsByWo = m.operations_by_wo || {};
      const salesOrders = m.sales_orders || [];
      const productionPlans = m.production_plans || [];

      // Donuts
      const donutRows = wos.map(wo=>({group: wo.status || "(No Status)", amount: Number(wo.qty||0)}));
      const jobCardDonutRows = jobCards.map(jc=>({group: jc.status || "(No Status)", amount: 1}));

      // Trend rows (planned vs produced by planned_start_date)
      const trendRows = wos.map(wo=>({
        date: wo.planned_start_date,
        planned: Number(wo.qty||0),
        produced: Number(wo.produced_qty||0)
      }));

      // Work Orders table
      const tableWORows = wos.map(wo=>{
        const qty = Number(wo.qty||0);
        const prod = Number(wo.produced_qty||0);
        const remaining = Math.max(qty - prod, 0);
        const pct = qty ? (prod/qty)*100 : 0;
        return {
          planned_start_date: String(wo.planned_start_date || "").slice(0,10),
          planned_end_date: String(wo.planned_end_date || "").slice(0,10),
          name: wo.name,
          production_item: wo.production_item,
          item_name: wo.item_name || "",
          qty: qty,
          produced_qty: prod,
          remaining_qty: remaining,
          "completion_%": Number(pct.toFixed(1)),
          status: wo.status,
          company: wo.company
        };
      });

      // Operations table (flatten)
      const tableOPRows = [];
      Object.keys(opsByWo||{}).forEach(woName=>{
        (opsByWo[woName]||[]).forEach(op=>{
          tableOPRows.push({
            "Work Order": woName,
            "Operation": op.operation || "",
            "Workstation": op.workstation || "",
            "Status": op.status || "",
            "Time (Mins)": Number(op.time_in_mins || 0),
            "Completed Qty": Number(op.completed_qty || 0)
          });
        });
      });

      // Job Cards table
      const tableJCRows = jobCards.map(jc => ({
        "Job Card": jc.name || "",
        "Work Order": jc.work_order || "",
        "Production Item": jc.production_item || "",
        "Operation": jc.operation || "",
        "Workstation": jc.workstation || "",
        "Workstation Type": jc.workstation_type || "",
        "Posting Date": jc.posting_date ? String(jc.posting_date).slice(0,10) : "",
        "Status": jc.status || "",
        "For Qty": Number(jc.for_quantity || 0),
        "Completed Qty": Number(jc.total_completed_qty || 0),
        "Process Loss Qty": Number(jc.process_loss_qty || 0),
        "Expected Start": jc.expected_start_date ? String(jc.expected_start_date).slice(0,19).replace("T", " ") : "",
        "Expected End": jc.expected_end_date ? String(jc.expected_end_date).slice(0,19).replace("T", " ") : "",
        "Actual Start": jc.actual_start_date ? String(jc.actual_start_date).slice(0,19).replace("T", " ") : "",
        "Actual End": jc.actual_end_date ? String(jc.actual_end_date).slice(0,19).replace("T", " ") : "",
        "Time Required (Mins)": Number(jc.time_required || 0),
        "Total Time (Mins)": Number(jc.total_time_in_mins || 0),
        "Company": jc.company || ""
      }));

      const tableJCStatusRows = jobCards.map(jc => ({
        "Job Card Number": jc.name || "",
        "Date": jc.posting_date ? String(jc.posting_date).slice(0,10) : "",
        "Work Order": jc.work_order || "",
        "Item Name": jc.item_name || jc.production_item || "",
        "Status": jc.status || ""
      }));

      const soWoMap = {};
      const soPpMap = {};
      const ppWoMap = {};
      const ppSoMap = {};
      wos.forEach(wo => {
        const so = wo.sales_order || "";
        const pp = wo.production_plan || "";
        const woNo = wo.name || "";
        if (so) {
          if (!soWoMap[so]) soWoMap[so] = [];
          if (woNo) soWoMap[so].push(woNo);
          if (pp) {
            if (!soPpMap[so]) soPpMap[so] = [];
            soPpMap[so].push(pp);
          }
        }
        if (pp) {
          if (!ppWoMap[pp]) ppWoMap[pp] = [];
          if (woNo) ppWoMap[pp].push(woNo);
          if (so) {
            if (!ppSoMap[pp]) ppSoMap[pp] = [];
            ppSoMap[pp].push(so);
          }
        }
      });

      const tableSORows = salesOrders.map(so => ({
        "Sales Order": so.name || "",
        "Date": so.transaction_date ? String(so.transaction_date).slice(0,10) : "",
        "Customer": so.customer || "",
        "Status": so.status || "",
        "Delivery Status": so.delivery_status || "",
        "Work Order No": Array.from(new Set(soWoMap[so.name] || [])).join(", "),
        "Production Plan No": Array.from(new Set(soPpMap[so.name] || [])).join(", ")
      }));

      const tablePPRows = productionPlans.map(pp => ({
        "Production Plan": pp.name || "",
        "Date": pp.posting_date ? String(pp.posting_date).slice(0,10) : "",
        "Status": pp.status || "",
        "Work Order No": Array.from(new Set(ppWoMap[pp.name] || [])).join(", "),
        "Sales Order No": Array.from(new Set(ppSoMap[pp.name] || [])).join(", ")
      }));

      // Employee logs table (original details + Work Order header rows)
      const detailEMPRows = employeeLogs.map(log => ({
        "Work Order": log.work_order || "(No Work Order)",
        "Job Card": log.job_card || "",
        "Employee": log.employee || "(No Employee)",
        "Operation": log.operation || "",
        "From Time": log.from_time ? String(log.from_time).slice(0,19).replace("T", " ") : "",
        "To Time": log.to_time ? String(log.to_time).slice(0,19).replace("T", " ") : "",
        "Time (Mins)": Number(log.time_in_mins || 0),
        "Completed Qty": Number(log.completed_qty || 0),
        "Production Item": log.production_item || "",
        "Item Name": log.item_name || "",
        "Company": log.company || ""
      }));

      detailEMPRows.sort((a, b) => {
        const woA = String(a["Work Order"] || "");
        const woB = String(b["Work Order"] || "");
        if (woA !== woB) return woA.localeCompare(woB);
        const jcA = String(a["Job Card"] || "");
        const jcB = String(b["Job Card"] || "");
        if (jcA !== jcB) return jcA.localeCompare(jcB);
        const tA = String(a["From Time"] || "");
        const tB = String(b["From Time"] || "");
        return tA.localeCompare(tB);
      });

      const tableEMPRows = [];
      let lastWO = null;
      detailEMPRows.forEach(row => {
        const currentWO = row["Work Order"] || "(No Work Order)";
        if (currentWO !== lastWO) {
          tableEMPRows.push({
            "Work Order": currentWO,
            "Job Card": "",
            "Employee": "",
            "Operation": "",
            "From Time": "",
            "To Time": "",
            "Time (Mins)": "",
            "Completed Qty": "",
            "Production Item": "",
            "Item Name": "",
            "Company": ""
          });
          lastWO = currentWO;
        }

        tableEMPRows.push({
          ...row,
          "Work Order": ""
        });
      });

      const detailByEmployee = employeeLogs.map(log => ({
        "Employee": log.employee || "(No Employee)",
        "Work Order": log.work_order || "",
        "Job Card": log.job_card || "",
        "Operation": log.operation || "",
        "From Time": log.from_time ? String(log.from_time).slice(0,19).replace("T", " ") : "",
        "To Time": log.to_time ? String(log.to_time).slice(0,19).replace("T", " ") : "",
        "Time (Mins)": Number(log.time_in_mins || 0),
        "Completed Qty": Number(log.completed_qty || 0),
        "Item Name": log.item_name || ""
      }));
      detailByEmployee.sort((a,b) => {
        const e = String(a["Employee"] || "").localeCompare(String(b["Employee"] || ""));
        if (e) return e;
        const w = String(a["Work Order"] || "").localeCompare(String(b["Work Order"] || ""));
        if (w) return w;
        const j = String(a["Job Card"] || "").localeCompare(String(b["Job Card"] || ""));
        if (j) return j;
        return String(a["From Time"] || "").localeCompare(String(b["From Time"] || ""));
      });
      const tableEMPByEmployeeRows = [];
      let lastEmp = null;
      detailByEmployee.forEach(r => {
        if (r["Employee"] !== lastEmp) {
          tableEMPByEmployeeRows.push({
            "Employee": r["Employee"],
            "Work Order": "",
            "Job Card": "",
            "Operation": "",
            "From Time": "",
            "To Time": "",
            "Time (Mins)": "",
            "Completed Qty": "",
            "Item Name": ""
          });
          lastEmp = r["Employee"];
        }
        tableEMPByEmployeeRows.push({
          ...r,
          "Employee": ""
        });
      });

      const d = m.distinct_values || {};
      return {
        donutRows,
        jobCardDonutRows,
        trendRows,
        tableWORows,
        tableOPRows,
        tableJCRows,
        tableJCStatusRows,
        tableSORows,
        tablePPRows,
        tableEMPRows,
        tableEMPByEmployeeRows,
        distinct: {
          companies: d.companies || [],
          groups: d.statuses || [],
          parties: d.production_items || [],
          extras: d.workstations || [],
          work_orders: (wos || []).map(wo => wo.name).filter(Boolean).sort((a,b)=>String(a).localeCompare(String(b))),
          sales_orders: d.sales_orders || []
        }
      };
    }
  };

  // ---- Exports ----
  function exportToCSV(rows, filename){
    if(!rows || !rows.length){
      if (typeof frappe !== "undefined" && frappe.msgprint) frappe.msgprint(__("No data to export."));
      return;
    }
    const header = Object.keys(rows[0]);
    const lines = [header.join(",")];
    rows.forEach(r=>{
      const line = header.map(h=>{
        const v = r[h];
        if(v===null || v===undefined) return "";
        const s = String(v).replace(/"/g,'""');
        return /[,"\n]/.test(s) ? `"${s}"` : s;
      }).join(",");
      lines.push(line);
    });
    const blob = new Blob([lines.join("\n")],{type:"text/csv;charset=utf-8;"});
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href=url; a.download=filename || "export.csv";
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }

  // ---- Debounce to prevent heavy re-render on each change ----
  function debounce(fn, wait){
    let t = null;
    return function(...args){
      clearTimeout(t);
      t = setTimeout(()=>fn.apply(this,args), wait);
    };
  }

  const reRenderDebounced = debounce(()=> {
    if(!dataLoaded || !cachedRawData) return;
    const filteredData = buildFilteredData();
    const out = window.DASH_CFG.transform(filteredData, buildArgs());
    currentOut = out;

    renderKPIs(filteredData, filteredData.work_orders);

    (async ()=>{
      await renderDonutOn(donutEl, groupForDonut(out.donutRows||[]), "Work Orders by Status (Planned Qty)");
      await renderDonutOn(jobCardDonutEl, groupForDonut(out.jobCardDonutRows||[]), "Job Cards by Status (Count)");
      const period = periodSelectorEl?.value || "daily";
      await renderTrendStacked(groupForPeriodStack(out.trendRows||[], period), "Planned vs Produced + Completion %", period);
      // Bottleneck + Productivity charts
      const bn = computeWorkstationBottlenecks(filteredData);
      await renderSimpleBar(bottleneckEl, bn.labels, bn.data, "Top Workstations by Time (mins)");
      const ep = computeEmployeeProductivity(filteredData);
      await renderSimpleBar(empProdEl, ep.labels, ep.data, "Top Employees by Qty/Hour");

    })();

    renderActiveTab();
    renderEmployeeSummary(filteredData);
  }, 350);

