      const jcRows = selectedWorkOrder ? (currentOut.tableJCRows||[]).filter(r=>r["Work Order"]===selectedWorkOrder) : currentOut.tableJCRows;
      const jcSummaryRows = selectedWorkOrder ? (currentOut.tableJCStatusRows||[]).filter(r=>r["Work Order"]===selectedWorkOrder) : currentOut.tableJCStatusRows;
      renderTable(tableJC, jcRows, window.DASH_CFG.columnsJC, "Job Cards", {
