    } else if(activeTab === "so"){
      tabTitleEl.textContent = "Sales Orders";
      tabHintEl.textContent = "Track Sales Order status and its linked Work Orders.";
      renderTable(tableSO, currentOut.tableSORows || [], window.DASH_CFG.columnsSO, "Sales Orders", {
        rowLimit: 1500,
        linkColumns: {
          "Sales Order": linkMap["Sales Order"]
        }
      });
    } else if(activeTab === "pp"){
      tabTitleEl.textContent = "Production Plans";
      tabHintEl.textContent = "Track Production Plan status and linked Work Orders.";
      renderTable(tablePP, currentOut.tablePPRows || [], window.DASH_CFG.columnsPP, "Production Plans", {
        rowLimit: 1500,
        linkColumns: {
          "Production Plan": linkMap["Production Plan"]
        }
