    } else if(activeTab === "emp"){
      tabTitleEl.textContent = "Employees";
      tabHintEl.textContent = selectedWorkOrder ? (`Filtered by Work Order: ${selectedWorkOrder}.`) : "Click Employee / Job Card / Work Order to open in ERPNext.";
      let empRows = currentOut.tableEMPRows || [];
      if (selectedWorkOrder) {
        const groupedRows = [];
        let includeGroup = false;
        empRows.forEach(r => {
          if (r["Work Order"]) {
            includeGroup = (r["Work Order"] === selectedWorkOrder);
          }
          if (includeGroup) groupedRows.push(r);
