      if (tableEMPByEmployee) {
        renderTable(tableEMPByEmployee, empByEmpRows, window.DASH_CFG.columnsEMPByEmployee, "Employee-wise Work/Job Cards", {
          rowLimit: 2500,
          preserveOrder: true,
