    }

    // Exports always export full transformed rows (not limited)
    if(exportBtn){
      exportBtn.onclick = ()=> exportToCSV(currentOut.tableWORows||[], window.DASH_CFG.exportName || "production_dashboard_export.csv");
    }
    if(exportJobCardBtn){
      exportJobCardBtn.onclick = ()=> exportToCSV(currentOut.tableJCRows||[], window.DASH_CFG.exportJobCardName || "job_card_export.csv");
    }
    if(exportEmployeeBtn){
      exportEmployeeBtn.onclick = ()=> exportToCSV(currentOut.tableEMPRows||[], window.DASH_CFG.exportEmployeeName || "employee_production_export.csv");
    }

    // Render Employee Production Summary
    if(dataLoaded && cachedRawData){
      const filteredData = buildFilteredData();
      renderEmployeeSummary(filteredData);
    }
  }

  function renderEmployeeSummary(filteredData){
    if(!tableEMPSummary) return;
    const logs = filteredData?.employee_time_logs || [];
    const jobCards = filteredData?.job_cards || [];

    function normalizeStatus(status){
      return String(status || "").trim().toLowerCase().replace(/\s+/g, " ");
    }

    function displayStatus(status){
      const norm = normalizeStatus(status);
      const known = {
        "completed": "Completed",
        "in process": "In Process",
        "open": "Open",
        "work in progress": "Work in Progress"
      };
      if (known[norm]) return known[norm];
      return String(status || "")
        .trim()
        .split(/\s+/)
        .map(w => w ? (w[0].toUpperCase() + w.slice(1).toLowerCase()) : "")
        .join(" ");
    }

    const jcStatusByName = {};
    const statusDisplayByNorm = {};
    jobCards.forEach(jc => {
      if (!jc?.name) return;
      const raw = String(jc.status || "").trim();
      const norm = normalizeStatus(raw);
      if (!norm) return;
      jcStatusByName[jc.name] = norm;
      if (!statusDisplayByNorm[norm]) {
        statusDisplayByNorm[norm] = displayStatus(raw);
      }
    });

    // Build status columns from job cards (show only available statuses).
    const statusNorms = Object.keys(statusDisplayByNorm);
    const preferred = ["completed", "in process", "open", "work in progress"];
    statusNorms.sort((a, b) => {
      const ai = preferred.indexOf(a);
      const bi = preferred.indexOf(b);
      if (ai !== -1 || bi !== -1) return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
      return statusDisplayByNorm[a].localeCompare(statusDisplayByNorm[b]);
    });
    const statusCols = statusNorms.map(n => statusDisplayByNorm[n]);

    // Group by employee and split qty by job card status.
    const empMap = {};
    const jcLoggedQty = {};
    const jcEmployees = {};

    function addQty(emp, statusNorm, qty){
      if(!empMap[emp]){
        empMap[emp] = {
          employee: emp,
          totalQty: 0,
          statusQty: {}
        };
      }
      empMap[emp].totalQty += qty;
      if (statusNorm && statusDisplayByNorm[statusNorm]) {
        const col = statusDisplayByNorm[statusNorm];
        empMap[emp].statusQty[col] = (empMap[emp].statusQty[col] || 0) + qty;
      }
    }

    logs.forEach(log => {
      const emp = log.employee || "(No Employee)";
      const qty = Number(log.completed_qty || 0);
      const jobCard = log.job_card || "";
      const statusNorm = jcStatusByName[log.job_card];
      addQty(emp, statusNorm, qty);

      if (jobCard) {
        jcLoggedQty[jobCard] = (jcLoggedQty[jobCard] || 0) + qty;
        if (!jcEmployees[jobCard]) jcEmployees[jobCard] = new Set();
        if (emp) jcEmployees[jobCard].add(emp);
      }
    });

    // Fallback: if Job Card has more total_completed_qty than summed time-log qty,
    // add the remainder (common in open/in-progress cards with partial logs).
    jobCards.forEach(jc => {
      const jcName = jc?.name;
      if (!jcName) return;
      const statusNorm = jcStatusByName[jcName];
      if (!statusNorm || !statusDisplayByNorm[statusNorm]) return;

      const jcTotalQty = Number(jc.total_completed_qty || 0);
      const loggedQty = Number(jcLoggedQty[jcName] || 0);
      const remainder = jcTotalQty - loggedQty;
      if (remainder <= 0.0001) return;

      const emps = Array.from(jcEmployees[jcName] || []);
      const targetEmp = emps.length ? emps[0] : "(No Employee)";
      addQty(targetEmp, statusNorm, remainder);
    });

    const summaryRows = Object.values(empMap).map(emp => {
      const row = {
        "Employee": emp.employee,
        "Total Qty": Math.round(emp.totalQty)
      };
      statusCols.forEach(col => {
        row[col] = Math.round(emp.statusQty[col] || 0);
      });
      return row;
    }).sort((a, b) => a.Employee.localeCompare(b.Employee));

    if(summaryRows.length === 0){
      tableEMPSummary.innerHTML = '<div style="padding:40px;text-align:center;color:#94a3b8;font-weight:600;">No employee data found</div>';
      return;
    }

    const thBase = 'padding:12px;text-align:right;font-weight:700;position:sticky;top:0;z-index:10;background:linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #0ea5e9 100%);';
    const thEmployee = 'padding:12px;text-align:left;font-weight:700;position:sticky;top:0;z-index:10;background:linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #0ea5e9 100%);';
    const statusHead = statusCols.map(col => `<th style="${thBase}">${escapeHtml(col)}</th>`).join("");
    const thead = `<tr style="background:linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #0ea5e9 100%);color:#fff;">
      <th style="${thEmployee}">Employee</th>
      <th style="${thBase}">Total Qty</th>
      ${statusHead}
    </tr>`;

    const tbody = summaryRows.map(row => `
      <tr style="border-bottom:1px solid #e5e7eb;transition:background 0.2s;" onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
        <td style="padding:12px;color:#334155;font-weight:600;">${escapeHtml(row.Employee)}</td>
        <td style="padding:12px;text-align:right;color:#1e293b;font-weight:700;font-family:monospace;">${fmt(row["Total Qty"])}</td>
        ${statusCols.map(col => `<td style="padding:12px;text-align:right;color:#1e293b;font-weight:700;font-family:monospace;">${fmt(row[col])}</td>`).join("")}
      </tr>
    `).join('');

    tableEMPSummary.innerHTML = `
      <div style="overflow-x:auto;max-height:600px;border:1px solid #e5e7eb;border-radius:8px;">
        <table style="width:100%;border-collapse:collapse;font-size:13px;">
          <thead>${thead}</thead>
          <tbody>${tbody}</tbody>
        </table>
      </div>
    `;
  }

  async function loadData(){
    const cfg = window.DASH_CFG || {};
    const apiMethod = cfg.apiMethod;
    if(!apiMethod){
      if(errorEl) errorEl.textContent = "Dashboard config missing: apiMethod";
      return;
    }
    if(loadingEl) loadingEl.style.display="block";
    if(errorEl) errorEl.textContent="";
    if(btn){ btn.disabled=true; btn.textContent="Fetching…"; }

    try{
      await ensureChartJSLibs();
      let args = buildArgs();
      if(!args.from_date || !args.to_date) throw new Error("Please select both From and To dates.");

      if(typeof document.DASH_BUILD_ARGS_OVERRIDE === "function"){
        args = document.DASH_BUILD_ARGS_OVERRIDE(args);
      }

      // IMPORTANT: keep API payload light for large ranges
      // You can tune these defaults in the server script too.
      args.limit_work_orders = args.limit_work_orders || 15000;
      args.limit_job_cards = args.limit_job_cards || 20000;
      args.limit_time_logs = args.limit_time_logs || 50000;

      const data = await callAPI(apiMethod, args);

      cachedRawData = data;
      cachedAllWorkOrders = data.work_orders || [];
      dataLoaded = true;

      const initialOut = cfg.transform(data, args);
      refreshDistinct(initialOut.distinct);

      // First render must respect currently selected filters
      const filteredData = buildFilteredData();
      const out = cfg.transform(filteredData, buildArgs());
      currentOut = out;
      if(lastRefreshEl) lastRefreshEl.textContent = nowStamp();

      renderKPIs(filteredData, filteredData.work_orders || []);
      await renderDonutOn(donutEl, groupForDonut(out.donutRows||[]), "Work Orders by Status (Planned Qty)");
      await renderDonutOn(jobCardDonutEl, groupForDonut(out.jobCardDonutRows||[]), "Job Cards by Status (Count)");
      const period = periodSelectorEl?.value || "daily";
      // Charts will be responsive now
      await renderTrendStacked(groupForPeriodStack(out.trendRows||[], period), "Planned vs Produced + Completion %", period);
      // Bottleneck + Productivity charts
      const bn = computeWorkstationBottlenecks(filteredData);
      await renderSimpleBar(bottleneckEl, bn.labels, bn.data, "Top Workstations by Time (mins)");
      const ep = computeEmployeeProductivity(filteredData);
      await renderSimpleBar(empProdEl, ep.labels, ep.data, "Top Employees by Qty/Hour");

      // Render Employee Summary
      renderEmployeeSummary(filteredData);


      renderActiveTab();

    }catch(e){
      console.error(e);
      if(errorEl) errorEl.textContent = "Error: " + (e.message || e);
    }finally{
      if(btn){ btn.disabled=false; btn.textContent="Load"; }
      if(loadingEl) loadingEl.style.display="none";
    }
  }

  function resetFilters(){
    [companyEl, groupEl, partyEl, extraEl, workOrderFilterEl, salesOrderFilterEl].forEach(el=>{ if(el) el.value=""; });
    selectedWorkOrder = "";
    if(woDrillPillEl) woDrillPillEl.style.display = "none";
    if(datePresetEl) datePresetEl.value = "this_year";
    setDatePreset("this_year");
  }

  function initTabs(){
    tabButtons.forEach(b=>{
      b.addEventListener("click", ()=>{
        tabButtons.forEach(x=>x.classList.remove("active"));
        b.classList.add("active");
        activeTab = b.dataset.tab;
        lastSearch = (searchEl?.value||"").trim();
        renderActiveTab();
      });
    });
  }

  function init(){
    injectStyles();
    setDefaultDates();
    initTabs();

    if(woDrillClearEl){
      woDrillClearEl.addEventListener("click", ()=>{
        selectedWorkOrder = "";
        if(woDrillPillEl) woDrillPillEl.style.display = "none";
        renderActiveTab();
      });
    }

    if(btn) btn.addEventListener("click", loadData);
    if(resetBtn) resetBtn.addEventListener("click", ()=>{
      resetFilters();
      if(dataLoaded) reRenderDebounced();
      else loadData();
    });

    if(datePresetEl) datePresetEl.addEventListener("change", (e)=>{
      if(e.target.value !== "custom") setDatePreset(e.target.value);
      reRenderDebounced();
    });

    // Debounced re-render on filter changes (huge performance win)
    [companyEl, groupEl, partyEl, extraEl, workOrderFilterEl, salesOrderFilterEl, fromDateEl, toDateEl, periodSelectorEl].forEach(el => {
      if(el) el.addEventListener("change", ()=>{
        if(datePresetEl && datePresetEl.value !== "custom" && el !== periodSelectorEl) datePresetEl.value = "custom";
        reRenderDebounced();
      });
    });

    if(searchEl){
      searchEl.addEventListener("input", debounce(()=>{
        lastSearch = (searchEl.value||"").trim();
        renderActiveTab();
      }, 200));
    }

    // Handle window resize/zoom to update chart sizes
    let resizeTimeout;
    window.addEventListener("resize", ()=>{
      clearTimeout(resizeTimeout);
      resizeTimeout = setTimeout(()=>{
        if(dataLoaded && cachedRawData){
          // Update all charts on resize
          const filteredData = buildFilteredData();
          const out = window.DASH_CFG.transform(filteredData, buildArgs());
          currentOut = out;

          (async ()=>{
            await renderDonutOn(donutEl, groupForDonut(out.donutRows||[]), "Work Orders by Status (Planned Qty)");
            await renderDonutOn(jobCardDonutEl, groupForDonut(out.jobCardDonutRows||[]), "Job Cards by Status (Count)");
            const period = periodSelectorEl?.value || "daily";
            await renderTrendStacked(groupForPeriodStack(out.trendRows||[], period), "Planned vs Produced + Completion %", period);
            const bn = computeWorkstationBottlenecks(filteredData);
            await renderSimpleBar(bottleneckEl, bn.labels, bn.data, "Top Workstations by Time (mins)");
            const ep = computeEmployeeProductivity(filteredData);
            await renderSimpleBar(empProdEl, ep.labels, ep.data, "Top Employees by Qty/Hour");
          })();
        }
      }, 300);
    });
  }

  if(document.readyState === "loading") document.addEventListener("DOMContentLoaded", init);
  else init();

  // Auto-load data when page opens
  setTimeout(() => {
    if(btn && fromDateEl && toDateEl && fromDateEl.value && toDateEl.value) {
      loadData();
    }
  }, 500);

})(typeof root_element !== "undefined" ? root_element : document);
